  const handleImportCustomerCSV = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const text = (e.target?.result as string || '').replace(/\r\n/g, '\n').replace(/\r/g, '\n');
        const lines = text.split('\n').filter(l => l.trim());
        if (lines.length < 2) {
          alert('CSV file is empty or has no data rows.');
          return;
        }
        const csvHeaders = lines[0].split(',').map(h => h.trim().toLowerCase());

        if (!csvHeaders.includes('name') && !csvHeaders.includes('customername')) {
          alert(`CSV is missing a required "name" column.\n\nFound columns: ${csvHeaders.join(', ')}`);
          return;
        }

        let workingCustomers = [...customers];
        let newCount = 0;
        let updatedCount = 0;
        let skippedRows = 0;
        for (let i = 1; i < lines.length; i++) {
          const values = lines[i].split(',').map(v => v.trim());
          const entry: any = {};
          csvHeaders.forEach((h, idx) => { entry[h] = values[idx] || ''; });

          const name = entry.name || entry.customername || '';
          if (!name) { skippedRows++; continue; }

          const id = entry.id || '';
          const customerNumber = entry.customernumber || entry.custno || '';
          const itasCustomerName = entry.itascustomername || entry.itas || '';
          const defaultLocation = (entry.defaultlocation || entry.location || 'Hamilton') as 'Hamilton' | 'Vancouver';
          const address = entry.address || '';
          const city = entry.city || '';
          const province = entry.province || entry.state || '';
          const postalCode = entry.postalcode || entry.postal || entry.zip || '';
          const defaultMargin = parseFloat(entry.defaultmargin || entry.margin || '0') || 0;
          const contactEmail = entry.contactemail || entry.email || '';
          const contactPhone = entry.contactphone || entry.phone || '';
          const qaContractEmail = entry.qacontractemail || entry.qaemail || '';
          const salesContactEmail = entry.salescontactemail || entry.salesemail || '';
          const customerServiceEmail = entry.customerserviceemail || '';
          const defaultPaymentTerms = entry.defaultpaymentterms || entry.paymentterms || '';
          const defaultCarrierCode = entry.defaultcarriercode || entry.carriercode || '';
          const notes = entry.notes || '';

          // Match by name, ID, or customerNumber
          const existingIdx = workingCustomers.findIndex(c =>
            c.name.toLowerCase() === name.toLowerCase() || (id && c.id === id) || (customerNumber && c.customerNumber === customerNumber)
          );
          if (existingIdx >= 0) {
            updatedCount++;
            const c = workingCustomers[existingIdx];
            workingCustomers[existingIdx] = {
              ...c,
              name: name || c.name,
              customerNumber: customerNumber || c.customerNumber,
              itasCustomerName: itasCustomerName || c.itasCustomerName,
              defaultLocation: entry.defaultlocation || entry.location ? defaultLocation : c.defaultLocation,
              address: address || c.address,
              city: city || c.city,
              province: province || c.province,
              postalCode: postalCode || c.postalCode,
              defaultMargin: defaultMargin || c.defaultMargin,
              contactEmail: contactEmail || c.contactEmail,
              contactPhone: contactPhone || c.contactPhone,
              qaContractEmail: qaContractEmail || c.qaContractEmail,
              salesContactEmail: salesContactEmail || c.salesContactEmail,
              customerServiceEmail: customerServiceEmail || c.customerServiceEmail,
              defaultPaymentTerms: defaultPaymentTerms || c.defaultPaymentTerms,
              defaultCarrierCode: defaultCarrierCode || c.defaultCarrierCode,
              notes: notes || c.notes,
            };
            continue;
          }

          newCount++;
          const newCustNum = customerNumber || getNextCustomerNumber(workingCustomers);
          workingCustomers.push({
            id: id || `CUST-${newCustNum}`,
            name,
            customerNumber: newCustNum,
            itasCustomerName: itasCustomerName || undefined,
            defaultLocation,
            address: address || undefined,
            city: city || undefined,
            province: province || undefined,
            postalCode: postalCode || undefined,
            defaultMargin,
            contactEmail: contactEmail || undefined,
            contactPhone: contactPhone || undefined,
            qaContractEmail: qaContractEmail || undefined,
            salesContactEmail: salesContactEmail || undefined,
            customerServiceEmail: customerServiceEmail || undefined,
            defaultPaymentTerms: defaultPaymentTerms || undefined,
            defaultCarrierCode: defaultCarrierCode || undefined,
            notes: notes || undefined,
          });
        }

        if (newCount > 0 || updatedCount > 0) {
          setCustomers(workingCustomers);
          syncCollection(COLLECTIONS.customers, workingCustomers).then(() => {
            lastSyncedData.current.customers = JSON.stringify(workingCustomers);
            setSyncStatus('synced');
            setLastSynced(new Date());
          }).catch(e => console.error('Customer sync failed:', e));
        }
        const parts: string[] = [];
        if (newCount > 0) parts.push(`${newCount} new customer${newCount > 1 ? 's' : ''} imported`);
        if (updatedCount > 0) parts.push(`${updatedCount} existing customer${updatedCount > 1 ? 's' : ''} updated`);
        if (skippedRows > 0) parts.push(`${skippedRows} row${skippedRows > 1 ? 's' : ''} skipped`);
        if (parts.length > 0) {
          alert(parts.join(', ') + '.');
        } else {
          alert('No customers could be imported. The file may be empty or in an unexpected format.');
        }
      } catch (err) {
        alert(`Error reading CSV file: ${err instanceof Error ? err.message : 'Unknown error'}`);
      }
    };
    reader.onerror = () => { alert('Failed to read the CSV file.'); };
    reader.readAsText(file);
    event.target.value = '';
  };

  const handleImportOrderCSV = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const text = (e.target?.result as string || '').replace(/\r\n/g, '\n').replace(/\r/g, '\n');
        const lines = text.split('\n').filter(l => l.trim());
        if (lines.length < 2) {
          alert('CSV file is empty or has no data rows.');
          return;
        }
        const rawHeaders = parseCSVRow(lines[0]);
        const headers = rawHeaders.map(normalizeHeader);

        // Require at least customer and product columns
        if (!headers.some(h => ['customer', 'customername', 'client'].includes(h))) {
          alert(`CSV is missing a required "customer" column.\n\nFound columns: ${rawHeaders.join(', ')}`);
          return;
        }

        const get = (entry: any, ...keys: string[]): string => {
          for (const k of keys) {
            const val = entry[k];
            if (val !== undefined && val !== '') return String(val);
          }
          return '';
        };

        let workingOrders = [...orders]; // Build final array directly
        let newCount = 0;
        let updatedCount = 0;
        let skippedRows = 0;
        for (let i = 1; i < lines.length; i++) {
          const values = parseCSVRow(lines[i]);
          const entry: any = {};
          headers.forEach((h, idx) => { entry[h] = values[idx] || ''; });

          const customer = get(entry, 'customer', 'customername', 'client', 'clientname', 'soldto');
          if (!customer) { skippedRows++; continue; }

          // Normalize dates
          const normalizeDate = (d: string) => {
            if (!d) return '';
            const m1 = d.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
            if (m1) return `${m1[3]}-${m1[1].padStart(2, '0')}-${m1[2].padStart(2, '0')}`;
            const months: Record<string, string> = { jan:'01', feb:'02', mar:'03', apr:'04', may:'05', jun:'06', jul:'07', aug:'08', sep:'09', oct:'10', nov:'11', dec:'12' };
            const m2 = d.match(/^(\d{1,2})[-\/](\w{3})[-\/](\d{4})$/i);
            if (m2) return `${m2[3]}-${months[m2[2].toLowerCase()] || '01'}-${m2[1].padStart(2, '0')}`;
            const m3 = d.match(/^(\d{1,2})\/(\d{1,2})\/(\d{2})$/);
            if (m3) return `20${m3[3]}-${m3[1].padStart(2, '0')}-${m3[2].padStart(2, '0')}`;
            return d;
          };
          const date = normalizeDate(get(entry, 'date', 'orderdate') || new Date().toISOString().split('T')[0]);
          const shipmentDate = normalizeDate(get(entry, 'shipmentdate', 'shipdate', 'shippingdate'));
          const deliveryDate = normalizeDate(get(entry, 'deliverydate', 'delivery'));

          const product = get(entry, 'product', 'productname', 'item', 'sku', 'description');
          const qty = parseLooseNumber(get(entry, 'qty', 'qtymt', 'quantity', 'volume', 'mt', 'weight'));
          const contractNumber = get(entry, 'contractnumber', 'contract', 'contractno', 'contract#');
          const pricePerMt = parseLooseNumber(get(entry, 'pricepermt', 'pricepmt', 'price', 'pricemt'));
          const amount = pricePerMt > 0 ? pricePerMt * qty : parseLooseNumber(get(entry, 'amount', 'total', 'totalamount'));
          const bolNumber = get(entry, 'bolnumber', 'bol', 'bolno', 'bol#', 'billoflading') || `ORD-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`;
          const splitNumber = get(entry, 'splitnumber', 'splitno', 'split', 'split#', 'splno');
          const currency = get(entry, 'currency', 'curr');

          const existingIdx = workingOrders.findIndex(o => o.bolNumber === bolNumber);
          if (existingIdx >= 0) {
            updatedCount++;
            const o = workingOrders[existingIdx];
            const updatedLineItems = o.lineItems.map((li, idx) => idx === 0 ? {
              ...li,
              productName: product || li.productName,
              qty: qty || li.qty,
              contractNumber: contractNumber || li.contractNumber,
              totalWeight: qty || li.totalWeight,
              unitAmount: amount > 0 ? amount / (qty || 1) : li.unitAmount,
              mtAmount: amount > 0 ? amount / (qty || 1) : li.mtAmount,
              lineAmount: amount || li.lineAmount
            } : li);
            workingOrders[existingIdx] = {
              ...o,
              customer: customer || o.customer,
              product: product || o.product,
              contractNumber: contractNumber || o.contractNumber,
              po: get(entry, 'po', 'ponumber', 'pono', 'po#', 'purchaseorder') || o.po,
              date: date || o.date,
              shipmentDate: shipmentDate || o.shipmentDate,
              deliveryDate: deliveryDate || o.deliveryDate,
              status: get(entry, 'status') ? (get(entry, 'status') as any) : o.status,
              amount: amount || o.amount,
              currency: currency || o.currency,
              splitNumber: splitNumber || o.splitNumber,
              carrier: get(entry, 'carrier', 'carriername', 'trucker', 'transport') || o.carrier,
              shippingTerms: (get(entry, 'shippingterms', 'terms', 'shipterms', 'incoterms') || o.shippingTerms) as any,
              location: get(entry, 'location', 'shiplocation', 'origin', 'warehouse') || o.location,
              palletType: (get(entry, 'pallettype', 'pallet') || o.palletType) as any,
              lineItems: updatedLineItems,
            };
            continue;
          }

          const lineItem: OrderLineItem = {
            id: `LI-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`,
            productName: product,
            qty,
            contractNumber,
            netWeightPerUnit: 0,
            totalWeight: qty,
            unitAmount: amount > 0 ? amount / (qty || 1) : 0,
            mtAmount: amount > 0 ? amount / (qty || 1) : 0,
            lineAmount: amount
          };

          newCount++;
          workingOrders.push({
            id: `ORD-${Date.now()}-${Math.random().toString(36).slice(2)}`,
            bolNumber,
            customer,
            product,
            contractNumber,
            po: get(entry, 'po', 'ponumber', 'pono', 'po#', 'purchaseorder'),
            date,
            shipmentDate: shipmentDate || undefined,
            deliveryDate: deliveryDate || undefined,
            status: (get(entry, 'status') === 'Confirmed' || get(entry, 'status') === 'Cancelled') ? get(entry, 'status') as any : 'Open',
            lineItems: [lineItem],
            amount,
            currency: currency || undefined,
            carrier: get(entry, 'carrier', 'carriername', 'trucker', 'transport'),
            shippingTerms: (get(entry, 'shippingterms', 'terms', 'shipterms', 'incoterms') || '') as any || '',
            location: get(entry, 'location', 'shiplocation', 'origin', 'warehouse'),
            splitNumber: splitNumber || undefined,
            palletType: (get(entry, 'pallettype', 'pallet') || '') as any || ''
          });
        }

        if (newCount > 0 || updatedCount > 0) {
          setOrders(workingOrders);
          // Immediately sync to Firebase
          syncCollection(COLLECTIONS.orders, workingOrders).then(() => {
            lastSyncedData.current.orders = JSON.stringify(workingOrders);
            setSyncStatus('synced');
            setLastSynced(new Date());
          }).catch(e => console.error('Order sync failed:', e));
        }
        const parts: string[] = [];
        if (newCount > 0) parts.push(`${newCount} new order${newCount > 1 ? 's' : ''} imported`);
        if (updatedCount > 0) parts.push(`${updatedCount} existing order${updatedCount > 1 ? 's' : ''} updated`);
        if (skippedRows > 0) parts.push(`${skippedRows} row${skippedRows > 1 ? 's' : ''} skipped`);
        if (parts.length > 0) {
          alert(parts.join(', ') + '.');
        } else {
          alert('No orders could be imported. The file may be empty or in an unexpected format.');
        }
      } catch (err) {
        alert(`Error reading CSV file: ${err instanceof Error ? err.message : 'Unknown error'}`);
      }
    };
    reader.onerror = () => { alert('Failed to read the CSV file.'); };
    reader.readAsText(file);
    event.target.value = '';
  };

  const handleImportInvoiceCSV = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const text = (e.target?.result as string || '').replace(/\r\n/g, '\n').replace(/\r/g, '\n');
        const lines = text.split('\n').filter(l => l.trim());
        if (lines.length < 2) {
          alert('CSV file is empty or has no data rows.');
          return;
        }
        const rawHeaders = parseCSVRow(lines[0]);
        const csvHeaders = rawHeaders.map(normalizeHeader);

        const hasBol = csvHeaders.some(h => ['bolnumber', 'bol', 'bolno', 'bol#', 'billoflading'].includes(h));
        if (!hasBol) {
          alert(`CSV is missing a required "bolNumber" column.\n\nFound columns: ${rawHeaders.join(', ')}`);
          return;
        }

        const normalizeDate = (d: string) => {
          if (!d) return '';
          const m1 = d.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
          if (m1) return `${m1[3]}-${m1[1].padStart(2, '0')}-${m1[2].padStart(2, '0')}`;
          const months: Record<string, string> = { jan:'01', feb:'02', mar:'03', apr:'04', may:'05', jun:'06', jul:'07', aug:'08', sep:'09', oct:'10', nov:'11', dec:'12' };
          const m2 = d.match(/^(\d{1,2})[-\/](\w{3})[-\/](\d{4})$/i);
          if (m2) return `${m2[3]}-${months[m2[2].toLowerCase()] || '01'}-${m2[1].padStart(2, '0')}`;
          const m3 = d.match(/^(\d{1,2})\/(\d{1,2})\/(\d{2})$/);
          if (m3) return `20${m3[3]}-${m3[1].padStart(2, '0')}-${m3[2].padStart(2, '0')}`;
          return d;
        };

        const get = (entry: any, ...keys: string[]): string => {
          for (const k of keys) {
            const val = entry[k];
            if (val !== undefined && val !== '') return String(val);
          }
          return '';
        };

        let workingInvoices = [...invoices];
        let newCount = 0;
        let updatedCount = 0;
        let skippedRows = 0;
        for (let i = 1; i < lines.length; i++) {
          const values = parseCSVRow(lines[i]);
          const entry: any = {};
          csvHeaders.forEach((h, idx) => { entry[h] = values[idx] || ''; });

          const bolNumber = get(entry, 'bolnumber', 'bol', 'bolno', 'bol#', 'billoflading');
          if (!bolNumber) { skippedRows++; continue; }

          const invoiceNumber = get(entry, 'invoicenumber', 'invoice', 'invoiceno', 'invoice#', 'invno', 'inv#');
          const customer = get(entry, 'customer', 'customername', 'client', 'clientname', 'soldto');
          const product = get(entry, 'product', 'productname', 'item', 'sku', 'description');
          const contractNumber = get(entry, 'contractnumber', 'contract', 'contractno', 'contract#');
          const po = get(entry, 'po', 'ponumber', 'pono', 'po#', 'purchaseorder');
          const date = normalizeDate(get(entry, 'date', 'invoicedate', 'invdate') || new Date().toISOString().split('T')[0]);
          const dueDate = normalizeDate(get(entry, 'duedate', 'due', 'paymentdue'));
          const qty = parseLooseNumber(get(entry, 'qty', 'qtymt', 'quantity', 'volume', 'mt', 'weight'));
          const pricePerMt = parseLooseNumber(get(entry, 'pricepermt', 'pricepmt', 'pricemt', 'price', 'pricepermetricton'));
          const amount = pricePerMt > 0 && qty > 0 ? Math.round(pricePerMt * qty * 100) / 100 : (parseLooseNumber(get(entry, 'amount', 'total', 'totalamount', 'invoiceamount', 'value')));
          const carrier = get(entry, 'carrier', 'carriername', 'trucker', 'transport');
          const status = get(entry, 'status', 'invoicestatus') || 'Pending';
          const splitNo = get(entry, 'splitno', 'split', 'splitnumber', 'split#', 'splno', 'splitnum');
          const shippingTerms = get(entry, 'shippingterms', 'terms', 'shipterms', 'incoterms');
          const location = get(entry, 'location', 'shiplocation', 'origin', 'warehouse');

          // Check if invoice with this BOL already exists — overwrite all fields from CSV
          const existingIdx = workingInvoices.findIndex(inv => inv.bolNumber === bolNumber);
          if (existingIdx !== -1) {
            updatedCount++;
            const inv = workingInvoices[existingIdx];
            workingInvoices[existingIdx] = {
              ...inv,
              invoiceNumber,
              customer,
              product,
              po,
              date,
              qty,
              pricePerMt: pricePerMt || undefined,
              amount,
              carrier,
              status,
              splitNo: splitNo || undefined,
              dueDate: dueDate || undefined,
              contractNumber: contractNumber || undefined,
              shippingTerms: shippingTerms || undefined,
              location: location || undefined,
            };
            continue;
          }

          newCount++;
          workingInvoices.push({
            id: `INV-${Date.now()}-${i}-${Math.random().toString(36).slice(2)}`,
            invoiceNumber: invoiceNumber || undefined,
            bolNumber,
            customer,
            product,
            po,
            qty,
            carrier,
            pricePerMt: pricePerMt || undefined,
            amount,
            shipmentId: '',
            date,
            status,
            splitNo: splitNo || undefined,
            dueDate: dueDate || undefined,
            contractNumber: contractNumber || undefined,
            shippingTerms: shippingTerms || undefined,
            location: location || undefined,
          });
        }

        // Set state and sync to Firebase with the same array — no race condition
        if (newCount > 0 || updatedCount > 0) {
          setInvoices(workingInvoices);
          syncCollection(COLLECTIONS.invoices, workingInvoices).then(() => {
            lastSyncedData.current.invoices = JSON.stringify(workingInvoices);
            setSyncStatus('synced');
            setLastSynced(new Date());
          }).catch(e => console.error('Invoice sync failed:', e));
        }
        const parts: string[] = [];
        if (newCount > 0) parts.push(`${newCount} new invoice${newCount > 1 ? 's' : ''} imported`);
        if (updatedCount > 0) parts.push(`${updatedCount} existing invoice${updatedCount > 1 ? 's' : ''} updated`);
        if (skippedRows > 0) parts.push(`${skippedRows} row${skippedRows > 1 ? 's' : ''} skipped`);
        if (parts.length > 0) {
          alert(parts.join(', ') + '.');
        } else {
          alert('No invoices could be imported. The file may be empty or in an unexpected format.');
        }
      } catch (err) {
        alert(`Error reading CSV file: ${err instanceof Error ? err.message : 'Unknown error'}`);
      }
    };
    reader.onerror = () => { alert('Failed to read the CSV file.'); };
    reader.readAsText(file);
    event.target.value = '';
  };

  // Robust CSV row parser that handles quoted fields with commas, newlines, and escaped quotes
  const parseCSVRow = (row: string): string[] => {
    const result: string[] = [];
    let current = '';
    let inQuotes = false;
    for (let i = 0; i < row.length; i++) {
      const ch = row[i];
      if (inQuotes) {
        if (ch === '"') {
          if (i + 1 < row.length && row[i + 1] === '"') {
            current += '"';
            i++; // skip escaped quote
          } else {
            inQuotes = false;
          }
        } else {
          current += ch;
        }
      } else {
        if (ch === '"') {
          inQuotes = true;
        } else if (ch === ',') {
          result.push(current.trim());
          current = '';
        } else {
          current += ch;
        }
      }
    }
    result.push(current.trim());
    return result;
  };

  // Normalize CSV header to a canonical key: strip spaces, special chars, lowercase
  // Normalize a CSV header to an alphanumeric key for fuzzy matching. Strips
  // ALL non-alphanumeric characters (spaces, _ - . # /, parentheses, etc.) so
  // headers like "Price/MT" and "Qty (MT)" collapse to "pricemt" / "qtymt" and
  // match the lookup keys instead of being dropped.
  const normalizeHeader = (h: string): string => h.trim().toLowerCase().replace(/[^a-z0-9]+/g, '');

  // Parse a numeric CSV value that may carry currency/thousands formatting, e.g.
  // "$713.37", "1,234.56", "$1,234.56", or "(50)" for a negative. Strips every
  // character except digits, a decimal point, and a leading minus so a price
  // like "$713.37" imports as 713.37 instead of NaN→0.
  const parseLooseNumber = (s: string | undefined): number => {
    if (!s) return 0;
    let cleaned = String(s).trim();
    // Accounting-style negatives: "(50)" -> "-50"
    if (/^\(.*\)$/.test(cleaned)) cleaned = '-' + cleaned.slice(1, -1);
    cleaned = cleaned.replace(/[^0-9.\-]/g, '');
    const n = parseFloat(cleaned);
    return isNaN(n) ? 0 : n;
  };

  const handleReplaceInvoiceCSV = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    if (!confirm(`This will REPLACE ALL invoices with only the records in this CSV file. Any existing invoices not in the CSV will be permanently removed.\n\nAre you sure you want to continue?`)) {
      event.target.value = '';
      return;
    }

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const text = (e.target?.result as string || '').replace(/\r\n/g, '\n').replace(/\r/g, '\n');
        const lines = text.split('\n').filter(l => l.trim());
        if (lines.length < 2) {
          alert('CSV file is empty or has no data rows.');
          return;
        }
        const rawHeaders = parseCSVRow(lines[0]);
        const csvHeaders = rawHeaders.map(normalizeHeader);

        // Debug: show what was parsed
        const hasBol = csvHeaders.some(h => ['bolnumber', 'bol', 'bolno', 'bol#'].includes(h));
        if (!hasBol) {
          alert(`CSV is missing a required "bolNumber" column.\n\nFound columns: ${rawHeaders.join(', ')}\n\nNormalized: ${csvHeaders.join(', ')}`);
          return;
        }

        const normalizeDate = (d: string) => {
          if (!d) return '';
          // MM/DD/YYYY
          const m1 = d.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
          if (m1) return `${m1[3]}-${m1[1].padStart(2, '0')}-${m1[2].padStart(2, '0')}`;
          // DD-MMM-YYYY (e.g. 15-Jan-2025)
          const months: Record<string, string> = { jan:'01', feb:'02', mar:'03', apr:'04', may:'05', jun:'06', jul:'07', aug:'08', sep:'09', oct:'10', nov:'11', dec:'12' };
          const m2 = d.match(/^(\d{1,2})[-\/](\w{3})[-\/](\d{4})$/i);
          if (m2) return `${m2[3]}-${months[m2[2].toLowerCase()] || '01'}-${m2[1].padStart(2, '0')}`;
          // M/D/YY
          const m3 = d.match(/^(\d{1,2})\/(\d{1,2})\/(\d{2})$/);
          if (m3) return `20${m3[3]}-${m3[1].padStart(2, '0')}-${m3[2].padStart(2, '0')}`;
          return d; // already YYYY-MM-DD or other format
        };

        const get = (entry: any, ...keys: string[]): string => {
          for (const k of keys) {
            const val = entry[k];
            if (val !== undefined && val !== '') return String(val);
          }
          return '';
        };

        const newInvoices: Invoice[] = [];
        let skippedRows = 0;
        for (let i = 1; i < lines.length; i++) {
          const values = parseCSVRow(lines[i]);
          const entry: any = {};
          csvHeaders.forEach((h, idx) => { entry[h] = values[idx] || ''; });

          const bolNumber = get(entry, 'bolnumber', 'bol', 'bolno', 'bol#', 'billoflading');
          if (!bolNumber) { skippedRows++; continue; }

          const invoiceNumber = get(entry, 'invoicenumber', 'invoice', 'invoiceno', 'invoice#', 'invno', 'inv#');
          const customer = get(entry, 'customer', 'customername', 'client', 'clientname', 'soldto');
          const product = get(entry, 'product', 'productname', 'item', 'sku', 'description');
          const contractNumber = get(entry, 'contractnumber', 'contract', 'contractno', 'contract#');
          const po = get(entry, 'po', 'ponumber', 'pono', 'po#', 'purchaseorder');
          const date = normalizeDate(get(entry, 'date', 'invoicedate', 'invdate') || new Date().toISOString().split('T')[0]);
          const dueDate = normalizeDate(get(entry, 'duedate', 'due', 'paymentdue', 'datedue'));
          const qty = parseLooseNumber(get(entry, 'qty', 'qtymt', 'quantity', 'volume', 'mt', 'weight'));
          const pricePerMt = parseLooseNumber(get(entry, 'pricepermt', 'pricepmt', 'pricemt', 'price', 'pricepermetricton'));
          const amount = pricePerMt > 0 && qty > 0 ? Math.round(pricePerMt * qty * 100) / 100 : (parseLooseNumber(get(entry, 'amount', 'total', 'totalamount', 'invoiceamount', 'value')));
          const carrier = get(entry, 'carrier', 'carriername', 'trucker', 'transport');
          const status = get(entry, 'status', 'invoicestatus') || 'Pending';
          const splitNo = get(entry, 'splitno', 'split', 'splitnumber', 'split#', 'splno', 'splitnum');
          const shippingTerms = get(entry, 'shippingterms', 'terms', 'shipterms', 'incoterms');
          const location = get(entry, 'location', 'shiplocation', 'origin', 'warehouse');

          // Preserve the existing ID if this BOL existed before
          const existingInv = invoices.find(inv => inv.bolNumber === bolNumber);

          newInvoices.push({
            id: existingInv?.id || `INV-${Date.now()}-${i}-${Math.random().toString(36).slice(2)}`,
            invoiceNumber: invoiceNumber || undefined,
            bolNumber,
            customer,
            product,
            po,
            qty,
            carrier,
            pricePerMt: pricePerMt || undefined,
            amount,
            shipmentId: existingInv?.shipmentId || '',
            date,
            status,
            splitNo: splitNo || undefined,
            dueDate: dueDate || undefined,
            contractNumber: contractNumber || undefined,
            shippingTerms: shippingTerms || undefined,
            location: location || undefined,
          });
        }

        const removedCount = invoices.length - invoices.filter(inv => newInvoices.some(n => n.bolNumber === inv.bolNumber)).length;

        setInvoices(newInvoices);
        syncCollection(COLLECTIONS.invoices, newInvoices).then(() => {
          lastSyncedData.current.invoices = JSON.stringify(newInvoices);
          setSyncStatus('synced');
          setLastSynced(new Date());
        }).catch(e => console.error('Invoice sync failed:', e));

        const parts: string[] = [];
        parts.push(`${newInvoices.length} invoice${newInvoices.length !== 1 ? 's' : ''} imported`);
        if (removedCount > 0) parts.push(`${removedCount} old invoice${removedCount !== 1 ? 's' : ''} removed`);
        if (skippedRows > 0) parts.push(`${skippedRows} row${skippedRows > 1 ? 's' : ''} skipped`);
        alert(parts.join(', ') + '.');
      } catch (err) {
        alert(`Error reading CSV file: ${err instanceof Error ? err.message : 'Unknown error'}`);
      }
    };
    reader.onerror = () => { alert('Failed to read the CSV file.'); };
    reader.readAsText(file);
    event.target.value = '';
  };

  const handleImportContractCSV = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const text = (e.target?.result as string || '').replace(/\r\n/g, '\n').replace(/\r/g, '\n');
        const lines = text.split('\n').filter(l => l.trim());
        if (lines.length < 2) {
          alert('CSV file is empty or has no data rows.');
          return;
        }
        const csvHeaders = lines[0].split(',').map(h => h.trim().toLowerCase());

        if (!csvHeaders.includes('contractnumber') && !csvHeaders.includes('contract')) {
          alert(`CSV is missing a required "contractNumber" column.\n\nFound columns: ${csvHeaders.join(', ')}`);
          return;
        }

        let workingContracts = [...contracts];
        let newCount = 0;
        let updatedCount = 0;
        let skippedRows = 0;
        for (let i = 1; i < lines.length; i++) {
          const values = lines[i].split(',').map(v => v.trim());
          const entry: any = {};
          csvHeaders.forEach((h, idx) => { entry[h] = values[idx] || ''; });

          const contractNumber = entry.contractnumber || entry.contract || '';
          if (!contractNumber) { skippedRows++; continue; }

          const normalizeDate = (d: string) => {
            const m = d.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
            return m ? `${m[3]}-${m[1].padStart(2, '0')}-${m[2].padStart(2, '0')}` : d;
          };

          const customerNumber = entry.customernumber || entry.custno || '';
          const customerName = entry.customername || entry.customer || '';
          const contractVolume = parseFloat(entry.contractvolume || entry.volume || '0') || 0;
          const volumeTaken = parseFloat(entry.volumetaken || '0') || 0;
          const startDate = normalizeDate(entry.startdate || entry.start || '');
          const endDate = normalizeDate(entry.enddate || entry.end || '');
          const skuName = entry.skuname || entry.sku || entry.product || '';
          const origin = entry.origin || '';
          const destination = entry.destination || '';
          const finalPrice = parseFloat(entry.pricemt || entry.finalprice || entry.price || '0') || 0;
          const currency = entry.currency || 'CAD';
          const notes = entry.notes || '';
          const shippingTerms = entry.shippingterms || '';
          const fxRate = parseFloat(entry.fxrate || entry.fx || '0') || 0;
          const rawPriceUsdMt = parseFloat(entry.rawpriceusdmt || entry.rawprice || '0') || 0;
          const deliveredFreight = parseFloat(entry.deliveredfreight || entry.freight || '0') || 0;
          const exportDuty = parseFloat(entry.exportduty || entry.duty || '0') || 0;
          const palletCharge = parseFloat(entry.palletcharge || '0') || 0;
          const paymentTerms = entry.paymentterms || '';
          const palletType = entry.pallettype || '';
          const margin = parseFloat(entry.margin || '0') || 0;
          const contractDate = entry.contractdate || entry.contract_date || '';
          const itasName = entry.itasname || entry.itas || '';

          // Check if contract with this number already exists — update in working array
          const existingIdx = workingContracts.findIndex(c => c.contractNumber === contractNumber);
          if (existingIdx !== -1) {
            updatedCount++;
            const c = workingContracts[existingIdx];
            const updatedVolume = contractVolume || c.contractVolume;
            const updatedTaken = volumeTaken || c.volumeTaken;
            workingContracts[existingIdx] = {
              ...c,
              customerNumber: customerNumber || c.customerNumber,
              customerName: customerName || c.customerName,
              contractVolume: updatedVolume,
              volumeTaken: updatedTaken,
              volumeOutstanding: updatedVolume - updatedTaken,
              startDate: startDate || c.startDate,
              endDate: endDate || c.endDate,
              skuName: skuName || c.skuName,
              origin: origin || c.origin,
              destination: destination || c.destination,
              finalPrice: finalPrice || c.finalPrice,
              currency: entry.currency ? currency : c.currency,
              notes: notes || c.notes,
              shippingTerms: shippingTerms || c.shippingTerms,
              fxRate: fxRate || c.fxRate,
              rawPriceUsdMt: rawPriceUsdMt || c.rawPriceUsdMt,
              deliveredFreight: deliveredFreight || c.deliveredFreight,
              exportDuty: exportDuty || c.exportDuty,
              palletCharge: palletCharge || c.palletCharge,
              paymentTerms: paymentTerms || c.paymentTerms,
              palletType: (palletType || c.palletType) as any,
              margin: margin || c.margin,
              contractDate: contractDate || c.contractDate,
              itasName: itasName || c.itasName,
            };
            continue;
          }

          newCount++;
          workingContracts.push({
            id: `CON-${Date.now()}-${Math.random().toString(36).slice(2)}`,
            contractNumber,
            customerNumber,
            customerName,
            contractVolume,
            volumeTaken,
            volumeOutstanding: contractVolume - volumeTaken,
            startDate,
            endDate,
            skuName,
            origin,
            destination,
            finalPrice,
            currency,
            notes: notes || undefined,
            shippingTerms: shippingTerms || undefined,
            fxRate: fxRate || undefined,
            rawPriceUsdMt: rawPriceUsdMt || undefined,
            deliveredFreight: deliveredFreight || undefined,
            exportDuty: exportDuty || undefined,
            palletCharge: palletCharge || undefined,
            paymentTerms: paymentTerms || undefined,
            palletType: (palletType || undefined) as any,
            margin: margin || undefined,
            active: true,
            ...(contractDate ? { contractDate } : {}),
            ...(itasName ? { itasName } : {}),
          });
        }

        // Set state and sync to Firebase with the same array — no race condition
        if (newCount > 0 || updatedCount > 0) {
          setContracts(workingContracts);
          syncCollection(COLLECTIONS.contracts, workingContracts).then(() => {
            lastSyncedData.current.contracts = JSON.stringify(workingContracts);
            setSyncStatus('synced');
            setLastSynced(new Date());
          }).catch(e => console.error('Contract sync failed:', e));
        }
        const parts: string[] = [];
        if (newCount > 0) parts.push(`${newCount} new contract${newCount > 1 ? 's' : ''} imported`);
        if (updatedCount > 0) parts.push(`${updatedCount} existing contract${updatedCount > 1 ? 's' : ''} updated`);
        if (skippedRows > 0) parts.push(`${skippedRows} row${skippedRows > 1 ? 's' : ''} skipped`);
        if (parts.length > 0) {
          alert(parts.join(', ') + '.');
        } else {
          alert('No contracts could be imported. The file may be empty or in an unexpected format.');
        }
      } catch (err) {
        alert(`Error reading CSV file: ${err instanceof Error ? err.message : 'Unknown error'}`);
      }
    };
    reader.onerror = () => { alert('Failed to read the CSV file.'); };
    reader.readAsText(file);
    event.target.value = '';
  };

  const handleImportCSV = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const text = (e.target?.result as string || '').replace(/\r\n/g, '\n').replace(/\r/g, '\n');
        const lines = text.split('\n').filter(l => l.trim());
        if (lines.length < 2) {
          alert('CSV file is empty or has no data rows. Expected at least a header row and one data row.');
          return;
        }
        const headers = lines[0].split(',').map(h => h.trim().toLowerCase());

        if (!headers.includes('date')) {
          alert(`CSV is missing a required "date" column.\n\nFound columns: ${headers.join(', ')}\n\nUse the Template button to download the expected format.`);
          return;
        }

        const newShipments: Shipment[] = [];
        let skippedRows = 0;
        for (let i = 1; i < lines.length; i++) {
          const values = lines[i].split(',').map(v => v.trim());
          const entry: any = {};
          headers.forEach((h, idx) => {
            entry[h] = values[idx] || '';
          });

          if (!entry.date) { skippedRows++; continue; }

          // Normalize date: accept M/D/YYYY, MM/DD/YYYY, YYYY-MM-DD
          let date = entry.date.trim();
          const slashMatch = date.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
          if (slashMatch) {
            const [, m, d, yr] = slashMatch;
            date = `${yr}-${m.padStart(2, '0')}-${d.padStart(2, '0')}`;
          }

          let week = entry.week;
          let day = entry.day;
          try {
            if (!week) week = `Week ${getWeekNumber(date)}`;
            if (!day) day = new Intl.DateTimeFormat('en-US', { weekday: 'long' }).format(new Date(date + 'T12:00:00'));
          } catch {
            skippedRows++;
            continue;
          }

          // Normalize time: convert "1:30:00 PM" or "13:30:00" to "13:30"
          let time = (entry.time || '08:00').trim();
          const timeMatch = time.match(/^(\d{1,2}):(\d{2})(?::(\d{2}))?\s*(AM|PM)?$/i);
          if (timeMatch) {
            let [, h, min, , ampm] = timeMatch;
            let hour = parseInt(h);
            if (ampm) {
              if (ampm.toUpperCase() === 'PM' && hour !== 12) hour += 12;
              if (ampm.toUpperCase() === 'AM' && hour === 12) hour = 0;
            }
            time = `${hour.toString().padStart(2, '0')}:${min}`;
          }

          // Look up matching order by BOL to auto-fill missing fields
          const bol = entry.bol || '';
          const matchedOrder = bol ? orders.find(o => o.bolNumber === bol) : undefined;
          const matchedLi = matchedOrder?.lineItems[0];

          newShipments.push({
            id: entry.id || `SHIP-${Date.now()}-${Math.random().toString(36).slice(2)}`,
            week,
            date,
            day,
            time,
            bay: entry.bay || (locations.find(l => l.name.toLowerCase().includes((entry.location || scheduleLocation).toLowerCase()))?.bays[0] || ''),
            customer: entry.customer || matchedOrder?.customer || '',
            product: entry.product || matchedLi?.productName || matchedOrder?.product || '',
            contractNumber: entry.contractnumber || entry.contractNumber || matchedLi?.contractNumber || matchedOrder?.contractNumber || '',
            po: entry.po || matchedOrder?.po || '',
            bol,
            qty: parseFloat(entry.qty) || matchedLi?.totalWeight || 0,
            carrier: entry.carrier || matchedOrder?.carrier || '',
            arrive: entry.arrive || '',
            start: entry.start || '',
            out: entry.out || '',
            status: entry.status || 'Confirmed',
            notes: entry.notes || '',
            color: entry.color || '',
            scaledQty: parseFloat(entry.scaledqty || entry.scaledQty) || undefined,
            trailerNo: entry.trailerno || entry.trailerNo || '',
            colour: entry.colour || '',
            lotNumber: entry.lotnumber || entry.lotNumber || '',
            location: entry.location || '',
            deliveryDate: (() => {
              const dd = entry.deliverydate || entry.deliveryDate || '';
              const ddMatch = dd.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
              return ddMatch ? `${ddMatch[3]}-${ddMatch[1].padStart(2, '0')}-${ddMatch[2].padStart(2, '0')}` : (dd || matchedOrder?.deliveryDate || '');
            })()
          });
        }

        if (newShipments.length > 0) {
          // Partition rows by location — CSV 'location' column wins; falls back to the
          // currently selected schedule location when the field is blank.
          const byLoc: { hamilton: Shipment[]; vancouver: Shipment[] } = { hamilton: [], vancouver: [] };
          for (const s of newShipments) {
            const loc = (s.location || scheduleLocation).toLowerCase();
            if (loc.includes('hamilton')) byLoc.hamilton.push(s);
            else byLoc.vancouver.push(s);
          }

          // Merge a batch of incoming shipments into an existing array.
          const mergeInto = (existing: Shipment[], incoming: Shipment[]): { result: Shipment[]; newCount: number; updatedCount: number } => {
            const working = [...existing];
            const importSlots = new Set<string>();
            let newCount = 0;
            let updatedCount = 0;
            for (const s of incoming) {
              const key = `${s.week}|${s.day}|${s.time}|${s.bay}`;
              const existingIdx = working.findIndex(ex => `${ex.week}|${ex.day}|${ex.time}|${ex.bay}` === key);
              if (existingIdx >= 0) {
                const ex = working[existingIdx];
                const mergedBol = s.bol || ex.bol;
                const ord = mergedBol ? orders.find(o => o.bolNumber === mergedBol) : undefined;
                const ordLi = ord?.lineItems[0];
                working[existingIdx] = {
                  ...ex,
                  customer: s.customer || ex.customer || ord?.customer || '',
                  product: s.product || ex.product || ordLi?.productName || ord?.product || '',
                  contractNumber: s.contractNumber || ex.contractNumber || ordLi?.contractNumber || ord?.contractNumber || '',
                  po: s.po || ex.po || ord?.po || '',
                  bol: mergedBol || ex.bol,
                  qty: s.qty || ex.qty || ordLi?.totalWeight || 0,
                  carrier: s.carrier || ex.carrier || ord?.carrier || '',
                  arrive: s.arrive || ex.arrive,
                  start: s.start || ex.start,
                  out: s.out || ex.out,
                  status: s.status !== 'Confirmed' ? s.status : ex.status || s.status,
                  notes: s.notes || ex.notes,
                  color: s.color || ex.color,
                  scaledQty: s.scaledQty || ex.scaledQty,
                  trailerNo: s.trailerNo || ex.trailerNo,
                  lotNumber: s.lotNumber || ex.lotNumber,
                  lotNumbers: (s.lotNumbers && s.lotNumbers.length > 0) ? s.lotNumbers : ex.lotNumbers,
                  deliveryDate: s.deliveryDate || ex.deliveryDate || ord?.deliveryDate || '',
                  location: s.location || ex.location,
                };
                updatedCount++;
                continue;
              }
              if (importSlots.has(key)) continue;
              importSlots.add(key);
              newCount++;
              working.push(s);
            }
            return { result: working, newCount, updatedCount };
          };

          let finalHamilton = hamiltonShipments;
          let finalVancouver = vancouverShipments;
          let totalNew = 0;
          let totalUpdated = 0;

          if (byLoc.hamilton.length > 0) {
            const { result, newCount, updatedCount } = mergeInto(hamiltonShipments, byLoc.hamilton);
            finalHamilton = result;
            totalNew += newCount;
            totalUpdated += updatedCount;
          }
          if (byLoc.vancouver.length > 0) {
            const { result, newCount, updatedCount } = mergeInto(vancouverShipments, byLoc.vancouver);
            finalVancouver = result;
            totalNew += newCount;
            totalUpdated += updatedCount;
          }

          setHamiltonShipments(finalHamilton);
          setVancouverShipments(finalVancouver);

          // Sync merged data to Firebase
          if (totalNew > 0 || totalUpdated > 0) {
            const allShipments = [...finalHamilton, ...finalVancouver];
            syncCollection(COLLECTIONS.shipments, allShipments).then(() => {
              lastSyncedData.current.shipments = JSON.stringify(allShipments);
              setSyncStatus('synced');
              setLastSynced(new Date());
            }).catch(e => console.error('Shipment sync failed:', e));
          }
          const parts: string[] = [];
          if (totalNew > 0) parts.push(`${totalNew} new shipment${totalNew > 1 ? 's' : ''} imported`);
          if (totalUpdated > 0) parts.push(`${totalUpdated} existing shipment${totalUpdated > 1 ? 's' : ''} updated`);
          if (skippedRows > 0) parts.push(`${skippedRows} row${skippedRows > 1 ? 's' : ''} skipped (missing/invalid date)`);
          alert(parts.join(', ') + '.');
        } else {
          alert(`No shipments could be imported from the CSV.\n\n${skippedRows > 0 ? `${skippedRows} row(s) were skipped because they had missing or invalid dates.` : 'The file may be empty or in an unexpected format.'}\n\nUse the Template button to download the expected format.`);
        }
      } catch (err) {
        alert(`Error reading CSV file: ${err instanceof Error ? err.message : 'Unknown error'}. Please check the file format and try again.`);
      }
    };
    reader.onerror = () => {
      alert('Failed to read the CSV file. Please try again.');
    };
    reader.readAsText(file);
    // Reset input so the same file can be re-selected
    event.target.value = '';
  };
  const [user, setUser] = useState<User | null>(null);
  const [authLoading, setAuthLoading] = useState(true);

  const fetchMarketData = async () => {
    if (!user) return;
    setIsFetchingMarket(true);
    try {
      const data = await fetchCollection<any>(COLLECTIONS.marketData);
      if (data.length > 0) {
        setMarketData(data);
        setLastMarketUpdate(new Date().toISOString());

        const months = Array.from(new Set(data.map((d: any) => d.Month || d.month).filter(Boolean))) as string[];
        if (months.length > 0) {
          setConfig(prev => {
            const isIsoDate = (val: string | undefined) => val && /^\d{4}-\d{2}-\d{2}$/.test(val);
            return {
              ...prev,
              contractStartDate: (!prev.contractStartDate || isIsoDate(prev.contractStartDate)) ? months[0] : prev.contractStartDate,
              contractEndDate: (!prev.contractEndDate || isIsoDate(prev.contractEndDate)) ? months[Math.min(months.length - 1, 3)] : prev.contractEndDate
            };
          });
        }
      }
    } catch (e) {
      console.error("Failed to fetch market data:", e);
    } finally {
      setIsFetchingMarket(false);
    }
  };


  // Firebase auth state listener
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (firebaseUser) => {
      setUser(firebaseUser);
      setAuthLoading(false);
    });
    return () => unsubscribe();
  }, []);

  // Auto-maximize the Order Details modal whenever a new order is opened.
  useEffect(() => {
    if (viewingOrderCard) {
      setModalMaximized('order', true);
    }
  }, [viewingOrderCard?.id]);

  const handleGoogleSignIn = async () => {
    try {
      setSyncError(null);
      await signInWithPopup(auth, googleProvider);
    } catch (e: any) {
      console.error('Sign-in failed:', e);
      setSyncError(e.message || 'Sign-in failed');
    }
  };

  const handleSignOut = async () => {
    try {
      await signOut(auth);
      setSyncStatus('offline');
      setLastSynced(null);
    } catch (e) {
      console.error('Sign-out failed:', e);
    }
  };

  // Tiny HTML-escape so customer / order strings injected into the email
  // body can't break out of the template.
  const escapeHtml = (s: string): string =>
    String(s).replace(/[&<>"']/g, c => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[c] as string));

  /**
   * Low-level email send. All three document senders (order confirmation,
   * BOL, COA) share this pipeline:
   *   1. Pre-flight checks: enabled, testMode + testAddress, recipient
   *      address resolves.
   *   2. Write a "sending" row to emailLog (visible immediately even if
   *      the request crashes).
   *   3. POST the PDF (base64) to /api/send-email.
   *   4. Patch the log row with the outcome.
   * Idempotency-keyed per (type, recordId) so retries land on the same
   * log row instead of creating duplicates.
   */
  // Per-ship-to-location email routing. A ship-to location can override where its
  // documents are addressed: a COA email (Certificate of Analysis), a Customer
  // Service email (Order Confirmation / BOL / Return Order Confirmation), and a
  // Logistics email that is CC'd on the shipping documents. Each value falls back
  // to the customer-level address at the call site when the location leaves it blank.
  const shipToEmailRouting = (customer: Customer | undefined, shipToLocationId: string | undefined) => {
    const st = shipToLocationId ? customer?.shipToLocations?.find(l => l.id === shipToLocationId) : undefined;
    return {
      coa: (st?.coaEmail || '').trim(),
      customerService: (st?.customerServiceEmail || '').trim(),
      logistics: (st?.logisticsEmail || '').trim(),
    };
  };

  const runEmailSend = async (params: {
    type: EmailDocumentType;
    orderId?: string;
    shipmentId?: string;
    invoiceId?: string;
    customerName: string;
    recipientTo: string;
    recipientCc?: string[];
    subject: string;
    html: string;
    pdfBlob: Blob;
    filename: string;
    idempotencyRecordId: string;
    triggeredBy: 'automation' | 'manual' | 'retry';
  }): Promise<{ success: boolean; error?: string }> => {
    if (!emailSettings.enabled) {
      return { success: false, error: 'Email sending is disabled in the Email Center.' };
    }
    if (emailSettings.testMode && !emailSettings.testAddress) {
      return { success: false, error: 'Test mode is on but no test address is configured.' };
    }
    if (!params.recipientTo) {
      return { success: false, error: 'No recipient address resolved.' };
    }

    // CC = internal CC list (Email Center setting) plus any per-call recipients
    // (e.g. a ship-to location's Logistics email), de-duplicated and minus the To.
    const ccList = Array.from(new Set([
      ...(emailSettings.internalCc || []),
      ...(params.recipientCc || []),
    ].map(a => a.trim()).filter(Boolean))).filter(a => a.toLowerCase() !== params.recipientTo.trim().toLowerCase());

    const logId = `EMAIL-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
    const idemKey = idempotencyKey(params.type, params.idempotencyRecordId);
    const existing = emailLog.find(l => l.idempotencyKey === idemKey);
    const attemptCount = (existing?.attemptCount ?? 0) + 1;
    const initial: EmailLog = {
      id: logId,
      type: params.type,
      orderId: params.orderId,
      shipmentId: params.shipmentId,
      invoiceId: params.invoiceId,
      customerName: params.customerName,
      recipientTo: [params.recipientTo],
      recipientCc: ccList.length ? ccList : undefined,
      actualRecipientTo: emailSettings.testMode ? [emailSettings.testAddress] : [params.recipientTo],
      subject: params.subject,
      attachmentFilename: params.filename,
      attachmentSizeBytes: params.pdfBlob.size,
      status: 'sending',
      idempotencyKey: idemKey,
      attemptCount,
      testMode: !!emailSettings.testMode,
      triggeredBy: params.triggeredBy,
      triggeredByUser: user?.email || undefined,
      createdAt: new Date().toISOString(),
    };
    setEmailLog(prev => [initial, ...prev]);

    const result = await sendEmail({
      to: [params.recipientTo],
      cc: ccList.length ? ccList : undefined,
      subject: params.subject,
      html: params.html,
      attachment: params.pdfBlob,
      attachmentFilename: params.filename,
      testMode: !!emailSettings.testMode,
      testAddress: emailSettings.testAddress,
      fromName: emailSettings.fromName || undefined,
      fromAddress: emailSettings.fromAddress?.trim() || undefined,
      replyTo: emailSettings.replyToAddress?.trim() || undefined,
    });

    setEmailLog(prev => prev.map(l => l.id === logId ? {
      ...l,
      status: result.success ? 'sent' : 'failed',
      providerMessageId: result.messageId,
      error: result.error,
      sentAt: result.success ? new Date().toISOString() : l.sentAt,
      actualRecipientTo: result.actualTo || l.actualRecipientTo,
    } : l));

    return { success: result.success, error: result.error };
  };

  /**
   * Generate the order-confirmation PDF and email it to the customer's
   * customerServiceEmail via Resend. See runEmailSend for the shared
   * pipeline; this just resolves the recipient, builds the message, and
   * generates the PDF.
   */
  // Build the token map + line items for the Google-Sheet order-confirmation
  // template. Token names match the {{tokens}} the operator places in the sheet.
  const buildOrderConfirmationTokens = (
    order: Order,
    ctx: { customer?: Customer; carrier?: Carrier; shipperLocation?: Location; shipToLocation?: ShipToLocation },
  ): { tokens: Record<string, string>; lineItems: Array<Record<string, string>> } => {
    const { customer, carrier, shipperLocation, shipToLocation } = ctx;
    // Thousands-separated number strings so the sheet output matches the in-code
    // PDF: units up to 2 decimals, weights fixed at 2.
    const fmtUnits = (n: number) => n.toLocaleString('en-US', { maximumFractionDigits: 2 });
    const fmtKg = (n: number) => n.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
    let totalUnits = 0, totalNet = 0, totalGross = 0;
    const lineItems = (order.lineItems || []).map(li => {
      const qa = qaProducts.find(p => p.skuName === li.productName);
      const netKg = qa?.netWeightKg || li.netWeightPerUnit || 0;
      const grossKg = qa?.grossWeightKg || 0;
      const net = netKg * li.qty;
      const gross = grossKg * li.qty;
      totalUnits += li.qty; totalNet += net; totalGross += gross;
      return {
        description: li.productName || '',
        contract: (li.contractNumber || '').trim() || (order.contractNumber || '').trim(),
        units: li.qty != null ? fmtUnits(li.qty) : '',
        net: net ? fmtKg(net) : '',
        gross: gross ? fmtKg(gross) : '',
      };
    });
    const deliverName = shipToLocation ? `${customer?.name || order.customer || ''} — ${shipToLocation.name}` : (customer?.name || order.customer || '');
    const deliverAddr = shipToLocation ? [shipToLocation.addressLine1, shipToLocation.addressLine2].filter(Boolean).join(', ') : (customer?.address || '');
    const deliverCityProv = shipToLocation ? [shipToLocation.city, shipToLocation.province].filter(Boolean).join(', ') : [customer?.city, customer?.province].filter(Boolean).join(', ');
    const deliverPostal = shipToLocation ? (shipToLocation.postalCode || '') : (customer?.postalCode || '');
    const tokens: Record<string, string> = {
      order_date: order.date || '',
      po: order.po || '',
      pickup_date: order.shipmentDate || '',
      delivery_date: order.deliveryDate || '',
      consignee_name: customer?.name || order.customer || '',
      consignee_tel: customer?.contactPhone || '',
      consignee_email: customer?.contactEmail || customer?.salesContactEmail || '',
      carrier_name: carrier?.name || order.carrier || '',
      carrier_tel: carrier?.contactPhone || '',
      carrier_email: carrier?.contactEmail || '',
      deliver_name: deliverName,
      deliver_address: deliverAddr,
      deliver_city_province: deliverCityProv,
      deliver_postal: deliverPostal,
      shipper_name: shipperLocation?.name || order.location || '',
      shipper_address: shipperLocation?.address || '',
      shipper_city_province: shipperLocation ? [shipperLocation.city, shipperLocation.province].filter(Boolean).join(', ') : '',
      shipper_postal: shipperLocation?.postalCode || '',
      bol: order.bolNumber || '',
      total_units: totalUnits ? fmtUnits(totalUnits) : '',
      total_net: totalNet ? fmtKg(totalNet) : '',
      total_gross: totalGross ? fmtKg(totalGross) : '',
    };
    return { tokens, lineItems };
  };

  // Produce the order-confirmation PDF as a Blob. When an "Order Confirmation" QA
  // template with a Google Sheet is configured, render LITERALLY from that sheet
  // via the service account; otherwise fall back to the built-in PDF generator.
  const orderConfirmationBlob = async (order: Order): Promise<{ blob: Blob; filename: string }> => {
    const customer = customers.find(c => c.name === order.customer);
    const carrier = carriers.find(c => c.name === order.carrier);
    const shipperLocation = locations.find(l => l.name === order.location || l.locationCode === order.location);
    const shipToLocation = order.shipToLocationId ? customer?.shipToLocations?.find(l => l.id === order.shipToLocationId) : undefined;
    const filename = `Order_Confirmation_${order.bolNumber || 'draft'}_${(order.customer || 'customer').replace(/[^a-zA-Z0-9]/g, '_')}.pdf`;

    const tmpl = qaTemplates.find(t => t.type === 'Order Confirmation' && (t.googleSheetUrl || '').trim());
    const sheetId = tmpl ? extractSheetId(tmpl.googleSheetUrl) : null;
    if (sheetId) {
      try {
        const { tokens, lineItems } = buildOrderConfirmationTokens(order, { customer, carrier, shipperLocation, shipToLocation });
        const blob = await renderSheetTemplatePdf({
          sheetId, tokens, lineItems,
          // Right-align the quantity / weight columns and the totals in the sheet.
          numericFields: ['units', 'net', 'gross'],
          numericTokens: ['total_units', 'total_net', 'total_gross'],
        });
        return { blob, filename };
      } catch (e) {
        console.error('Order-confirmation template render failed; using the built-in PDF:', e);
      }
    }
    const gen = generateOrderConfirmationPdf({ order, customer, carrier, shipperLocation, shipToLocation, qaProducts, skus });
    const blob = await fetch(gen.blobUrl).then(r => r.blob());
    setTimeout(() => URL.revokeObjectURL(gen.blobUrl), 5000);
    return { blob, filename: gen.filename };
  };

  const sendOrderConfirmationEmail = async (order: Order, opts?: { triggeredBy?: 'automation' | 'manual' | 'retry' }) => {
    const customer = customers.find(c => c.name === order.customer);
    const routing = shipToEmailRouting(customer, order.shipToLocationId);
    const recipientTo = (routing.customerService || customer?.customerServiceEmail || '').trim();
    if (!recipientTo) {
      setErrorBox(`Cannot send — ${order.customer || 'this customer'} has no Customer Service email on file (set one on the ship-to location or the customer).`);
      return;
    }
    let pdfBlob: Blob;
    let filename: string;
    try {
      const r = await orderConfirmationBlob(order);
      pdfBlob = r.blob;
      filename = r.filename;
    } catch (e: any) {
      setErrorBox('Failed to generate the order confirmation PDF: ' + (e?.message || 'Unknown error'));
      return;
    }

    const totalKg = (order.lineItems || []).reduce((s, li) => s + (li.totalWeight || 0), 0) * 1000;
    const subject = `Order Confirmation — BOL ${order.bolNumber || order.id}`;
    const html = `
      <p>Hello ${escapeHtml(order.customer || '')},</p>
      <p>Please find attached the order confirmation for the order below.</p>
      <table cellspacing="0" cellpadding="6" style="border-collapse:collapse;font-family:Arial,sans-serif;font-size:13px;">
        <tr><td><strong>BOL Number</strong></td><td>${escapeHtml(order.bolNumber || '—')}</td></tr>
        <tr><td><strong>PO Number</strong></td><td>${escapeHtml(order.po || '—')}</td></tr>
        <tr><td><strong>Product</strong></td><td>${escapeHtml(order.product || order.lineItems?.[0]?.productName || '—')}</td></tr>
        <tr><td><strong>Total Weight</strong></td><td>${totalKg.toFixed(0)} kg</td></tr>
        <tr><td><strong>Shipment Date</strong></td><td>${escapeHtml(order.shipmentDate || '—')}</td></tr>
        <tr><td><strong>Carrier</strong></td><td>${escapeHtml(order.carrier || '—')}</td></tr>
      </table>
      <p>Thank you,<br/>${escapeHtml(emailSettings.fromName || 'Sucro Canada Sales')}</p>
    `.trim();

    const result = await runEmailSend({
      type: 'order_confirmation',
      orderId: order.id,
      customerName: order.customer || '',
      recipientTo,
      recipientCc: routing.logistics ? [routing.logistics] : undefined,
      subject, html,
      pdfBlob, filename,
      idempotencyRecordId: order.id,
      triggeredBy: opts?.triggeredBy || 'manual',
    });

    if (!result.success) {
      setErrorBox(`Order confirmation email failed: ${result.error || 'Unknown error'} — see Email Center.`);
    }
  };

  /** Resolve a shipment record for an order — falls back to a stub so the
   *  BOL/COA generators can still produce a PDF for orders that haven't
   *  had a shipment created yet. */
  const shipmentForOrder = (order: Order): Shipment => {
    const matched = [...hamiltonShipments, ...vancouverShipments].find(s => s.bol === order.bolNumber);
    if (matched) return matched;
    // Stub — mirrors what handleGenerateBol uses when no shipment is linked.
    return {
      id: `TMP-${order.id}`,
      week: '',
      date: order.shipmentDate || new Date().toISOString().split('T')[0],
      day: '',
      time: '',
      bay: '',
      customer: order.customer || '',
      product: order.product || order.lineItems?.[0]?.productName || '',
      po: order.po || '',
      bol: order.bolNumber || '',
      qty: (order.lineItems || []).reduce((s, li) => s + (li.totalWeight || 0), 0),
      carrier: order.carrier || '',
      arrive: '', start: '', out: '',
      status: order.status,
      contractNumber: order.contractNumber,
      location: order.location,
    };
  };

  /** Send the Bill of Lading PDF to the customer's customerServiceEmail. */
  const sendBolEmail = async (order: Order, opts?: { triggeredBy?: 'automation' | 'manual' | 'retry' }) => {
    const customer = customers.find(c => c.name === order.customer);
    const routing = shipToEmailRouting(customer, order.shipToLocationId);
    const recipientTo = (routing.customerService || customer?.customerServiceEmail || '').trim();
    if (!recipientTo) {
      setErrorBox(`Cannot send BOL — ${order.customer || 'this customer'} has no Customer Service email on file (set one on the ship-to location or the customer).`);
      return;
    }
    const shipment = shipmentForOrder(order);
    const carrier = carriers.find(c => c.name === shipment.carrier);
    const shipFromLoc = locations.find(l => l.name === (order.location || '') || l.locationCode === (order.location || ''));
    const shipToLoc = order.shipToLocationId
      ? customer?.shipToLocations?.find(l => l.id === order.shipToLocationId)
      : undefined;

    let blobUrl = '';
    let pdfBlob: Blob;
    let filename: string;
    try {
      const gen = generateBolPdf({
        shipment, order, customer, carrier,
        shipFromLocation: shipFromLoc,
        shipToCustomer: customer,
        shipToLocation: shipToLoc,
        qaProducts,
      });
      blobUrl = gen.blobUrl;
      filename = gen.filename;
      pdfBlob = await fetch(blobUrl).then(r => r.blob());
    } catch (e: any) {
      setErrorBox('Failed to generate the BOL PDF: ' + (e?.message || 'Unknown error'));
      return;
    }

    const totalKg = (order.lineItems || []).reduce((s, li) => s + (li.totalWeight || 0), 0) * 1000;
    const subject = `Bill of Lading — ${order.bolNumber || order.id}`;
    const html = `
      <p>Hello ${escapeHtml(order.customer || '')},</p>
      <p>Please find attached the Bill of Lading for the shipment below.</p>
      <table cellspacing="0" cellpadding="6" style="border-collapse:collapse;font-family:Arial,sans-serif;font-size:13px;">
        <tr><td><strong>BOL Number</strong></td><td>${escapeHtml(order.bolNumber || '—')}</td></tr>
        <tr><td><strong>PO Number</strong></td><td>${escapeHtml(order.po || '—')}</td></tr>
        <tr><td><strong>Product</strong></td><td>${escapeHtml(order.product || order.lineItems?.[0]?.productName || '—')}</td></tr>
        <tr><td><strong>Total Weight</strong></td><td>${totalKg.toFixed(0)} kg</td></tr>
        <tr><td><strong>Shipment Date</strong></td><td>${escapeHtml(order.shipmentDate || '—')}</td></tr>
        <tr><td><strong>Carrier</strong></td><td>${escapeHtml(order.carrier || '—')}</td></tr>
      </table>
      <p>Thank you,<br/>${escapeHtml(emailSettings.fromName || 'Sucro Canada Sales')}</p>
    `.trim();

    const result = await runEmailSend({
      type: 'bol',
      orderId: order.id,
      shipmentId: shipment.id,
      customerName: order.customer || '',
      recipientTo,
      recipientCc: routing.logistics ? [routing.logistics] : undefined,
      subject, html,
      pdfBlob, filename,
      idempotencyRecordId: order.id,
      triggeredBy: opts?.triggeredBy || 'manual',
    });

    if (blobUrl) setTimeout(() => URL.revokeObjectURL(blobUrl), 5000);
    if (!result.success) {
      setErrorBox(`BOL email failed: ${result.error || 'Unknown error'} — see Email Center.`);
    }
  };

  /* ──────────────────────────────────────────────────────────────────── */
  /*  RETURN ORDERS — helpers, send, return-and-bill                       */
  /* ──────────────────────────────────────────────────────────────────── */

  /** Generate the next R-prefixed BOL number, e.g. "R000007". Scans every
   *  existing return order + every regular order (so a return can't collide
   *  with an R-prefixed manual outbound BOL) and increments. */
  const generateReturnBolNumber = (): string => {
    const candidates: string[] = [
      ...returnOrders.map(r => r.bolNumber || ''),
      ...orders.map(o => o.bolNumber || ''),
      ...invoices.map(i => i.bolNumber || ''),
    ];
    let max = 0;
    for (const b of candidates) {
      const m = /^R(\d{1,6})$/.exec((b || '').trim());
      if (m) max = Math.max(max, parseInt(m[1], 10));
    }
    const next = max + 1;
    return `R${String(next).padStart(6, '0')}`;
  };

  /** Build a draft return order from an existing invoice (or fallback order).
   *  Copies line items, pricing, qty, contract, etc. — caller fills in the
   *  reason and any overrides before saving. */
  const buildReturnOrderDraftFromInvoice = (inv: Invoice): ReturnOrder => {
    const linkedOrder = orders.find(o => o.bolNumber === inv.bolNumber);
    return {
      id: `RTN-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
      bolNumber: '', // assigned on save via generateReturnBolNumber
      originalBolNumber: inv.bolNumber || '',
      originalInvoiceId: inv.id,
      customer: inv.customer || '',
      product: inv.product || '',
      contractNumber: inv.contractNumber || linkedOrder?.contractNumber || '',
      po: inv.po || '',
      date: new Date().toISOString().split('T')[0],
      shipmentDate: '',
      deliveryDate: '',
      status: 'Open',
      lineItems: (inv.lineItems || linkedOrder?.lineItems || []).map(li => ({
        ...li,
        id: `LI-RTN-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`,
      })),
      amount: inv.amount || 0,
      carrier: inv.carrier || linkedOrder?.carrier || '',
      shippingTerms: (inv.shippingTerms as any) || linkedOrder?.shippingTerms || '',
      location: inv.location || linkedOrder?.location || '',
      splitNumber: inv.splitNo || linkedOrder?.splitNumber || '',
      currency: linkedOrder?.currency || 'CAD',
      palletType: linkedOrder?.palletType || '',
      shipToLocationId: linkedOrder?.shipToLocationId,
      reasonForReturn: '',
    };
  };

  /** Preview the Return Order Confirmation PDF in the pdfPreview modal. */
  const handlePreviewReturnOrderConfirmation = (returnOrder: ReturnOrder) => {
    try {
      const customer = customers.find(c => c.name === returnOrder.customer);
      const carrier = carriers.find(c => c.name === returnOrder.carrier);
      const shipperLocation = locations.find(l => l.name === returnOrder.location || l.locationCode === returnOrder.location);
      const shipToLocation = returnOrder.shipToLocationId
        ? customer?.shipToLocations?.find(l => l.id === returnOrder.shipToLocationId)
        : undefined;
      // The return-order shape matches Order closely; pass it through the
      // generator with documentType='return_order_confirmation' so the title
      // / reason / original-BOL adaptations kick in.
      const { blobUrl, filename } = generateOrderConfirmationPdf({
        order: returnOrder as unknown as Order,
        customer, carrier, shipperLocation, shipToLocation,
        qaProducts, skus,
        documentType: 'return_order_confirmation',
        reasonForReturn: returnOrder.reasonForReturn,
        originalBolNumber: returnOrder.originalBolNumber,
      });
      if (pdfPreview?.url) URL.revokeObjectURL(pdfPreview.url);
      setPdfPreview({ url: blobUrl, filename, templateType: 'Return Order Confirmation' });
    } catch (e: any) {
      console.error('Generate return-order confirmation failed:', e);
      setErrorBox('Failed to generate Return Order Confirmation: ' + (e?.message || 'Unknown error'));
    }
  };

  /** Email the Return Order Confirmation PDF to customerServiceEmail. */
  const sendReturnOrderConfirmationEmail = async (returnOrder: ReturnOrder, opts?: { triggeredBy?: 'automation' | 'manual' | 'retry' }) => {
    const customer = customers.find(c => c.name === returnOrder.customer);
    const routing = shipToEmailRouting(customer, returnOrder.shipToLocationId);
    const recipientTo = (routing.customerService || customer?.customerServiceEmail || '').trim();
    if (!recipientTo) {
      setErrorBox(`Cannot send — ${returnOrder.customer || 'this customer'} has no Customer Service email on file (set one on the ship-to location or the customer).`);
      return;
    }
    const carrier = carriers.find(c => c.name === returnOrder.carrier);
    const shipperLocation = locations.find(l => l.name === returnOrder.location || l.locationCode === returnOrder.location);
    const shipToLocation = returnOrder.shipToLocationId
      ? customer?.shipToLocations?.find(l => l.id === returnOrder.shipToLocationId)
      : undefined;

    let blobUrl = '';
    let pdfBlob: Blob;
    let filename: string;
    try {
      const gen = generateOrderConfirmationPdf({
        order: returnOrder as unknown as Order,
        customer, carrier, shipperLocation, shipToLocation,
        qaProducts, skus,
        documentType: 'return_order_confirmation',
        reasonForReturn: returnOrder.reasonForReturn,
        originalBolNumber: returnOrder.originalBolNumber,
      });
      blobUrl = gen.blobUrl;
      filename = gen.filename;
      pdfBlob = await fetch(blobUrl).then(r => r.blob());
    } catch (e: any) {
      setErrorBox('Failed to generate the return-order PDF: ' + (e?.message || 'Unknown error'));
      return;
    }

    const totalKg = (returnOrder.lineItems || []).reduce((s, li) => s + (li.totalWeight || 0), 0) * 1000;
    const subject = `Return Order Confirmation — ${returnOrder.bolNumber || returnOrder.id} (Original ${returnOrder.originalBolNumber || '—'})`;
    const html = `
      <p>Hello ${escapeHtml(returnOrder.customer || '')},</p>
      <p>Please find attached the Return Order Confirmation for the return below.</p>
      <table cellspacing="0" cellpadding="6" style="border-collapse:collapse;font-family:Arial,sans-serif;font-size:13px;">
        <tr><td><strong>Return BOL</strong></td><td>${escapeHtml(returnOrder.bolNumber || '—')}</td></tr>
        <tr><td><strong>Original BOL</strong></td><td>${escapeHtml(returnOrder.originalBolNumber || '—')}</td></tr>
        <tr><td><strong>PO Number</strong></td><td>${escapeHtml(returnOrder.po || '—')}</td></tr>
        <tr><td><strong>Product</strong></td><td>${escapeHtml(returnOrder.product || returnOrder.lineItems?.[0]?.productName || '—')}</td></tr>
        <tr><td><strong>Total Weight</strong></td><td>${totalKg.toFixed(0)} kg</td></tr>
        <tr><td><strong>Reason for Return</strong></td><td>${escapeHtml(returnOrder.reasonForReturn || '—')}</td></tr>
      </table>
      <p>Thank you,<br/>${escapeHtml(emailSettings.fromName || 'Sucro Canada')}</p>
    `.trim();

    const result = await runEmailSend({
      type: 'return_order_confirmation',
      orderId: returnOrder.id,
      customerName: returnOrder.customer || '',
      recipientTo,
      recipientCc: routing.logistics ? [routing.logistics] : undefined,
      subject, html,
      pdfBlob, filename,
      idempotencyRecordId: returnOrder.id,
      triggeredBy: opts?.triggeredBy || 'manual',
    });

    if (blobUrl) setTimeout(() => URL.revokeObjectURL(blobUrl), 5000);
    if (!result.success) {
      setErrorBox(`Return order confirmation email failed: ${result.error || 'Unknown error'} — see Email Center.`);
    }
  };

  /** Complete a return order: assign the R-BOL, flip status to Completed,
   *  and post a NEGATIVE invoice referencing the original. */
  const returnAndBillOrder = (returnOrderId: string) => {
    const ro = returnOrders.find(r => r.id === returnOrderId);
    if (!ro) return;
    if (ro.status === 'Completed') return;

    // 1. Assign R-BOL if it doesn't already have one.
    const bol = ro.bolNumber && /^R\d{6}$/.test(ro.bolNumber) ? ro.bolNumber : generateReturnBolNumber();
    const totalWeightMT = ro.lineItems.reduce((s, li) => s + (li.totalWeight || 0), 0);

    // 2. Update the return order — Completed, with the final BOL.
    setReturnOrders(prev => prev.map(r => r.id === returnOrderId ? { ...r, bolNumber: bol, status: 'Completed' } : r));

    // 3. Create the credit invoice. We post a NEGATIVE amount so finance
    //    can offset the original sale. Tagged with status "Credit" so it's
    //    clear in the invoices table.
    const creditAmount = -Math.abs(ro.amount || 0);
    const creditInvoiceId = `INV-RTN-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;
    const creditInvoice: Invoice = {
      id: creditInvoiceId,
      bolNumber: bol,
      customer: ro.customer,
      product: ro.product || ro.lineItems.map(li => li.productName).join(', '),
      po: ro.po,
      qty: totalWeightMT,
      carrier: ro.carrier || '',
      amount: creditAmount,
      shipmentId: ro.id,
      date: new Date().toISOString().split('T')[0],
      status: 'Credit',
      lineItems: ro.lineItems,
      shippingTerms: ro.shippingTerms || '',
      location: ro.location || '',
      contractNumber: ro.contractNumber || '',
    };
    setInvoices(prev => prev.some(i => i.shipmentId === ro.id && i.status === 'Credit') ? prev : [...prev, creditInvoice]);

    // 4. Fire the confirmation email automatically when its trigger is on.
    if (emailSettings.enabled && emailSettings.triggers.orderConfirmationOnConfirmed) {
      sendReturnOrderConfirmationEmail({ ...ro, bolNumber: bol, status: 'Completed' }, { triggeredBy: 'automation' });
    }
  };

  /** Send the Certificate of Analysis PDF. Routed to the customer's
   *  qaContractEmail when set (the contact your QA team established with
   *  the customer's quality dept), falling back to customerServiceEmail. */
  const sendCoaEmail = async (order: Order, opts?: { triggeredBy?: 'automation' | 'manual' | 'retry' }) => {
    const customer = customers.find(c => c.name === order.customer);
    const routing = shipToEmailRouting(customer, order.shipToLocationId);
    const recipientTo = (routing.coa || customer?.qaContractEmail || customer?.customerServiceEmail || '').trim();
    if (!recipientTo) {
      setErrorBox(`Cannot send COA — ${order.customer || 'this customer'} has no COA / QA Contract / Customer Service email on file (set one on the ship-to location or the customer).`);
      return;
    }
    const shipment = shipmentForOrder(order);
    const shipFromLoc = locations.find(l => l.name === (order.location || '') || l.locationCode === (order.location || ''));

    let blobUrl = '';
    let pdfBlob: Blob;
    let filename: string;
    try {
      const gen = generateCoaPdf({
        shipment, order, customer,
        shipFromLocation: shipFromLoc,
        lotCodes, qaProducts,
      });
      blobUrl = gen.blobUrl;
      filename = gen.filename;
      pdfBlob = await fetch(blobUrl).then(r => r.blob());
    } catch (e: any) {
      setErrorBox('Failed to generate the COA PDF: ' + (e?.message || 'Unknown error'));
      return;
    }

    const subject = `Certificate of Analysis — ${order.bolNumber || order.id}`;
    const html = `
      <p>Hello ${escapeHtml(order.customer || '')},</p>
      <p>Please find attached the Certificate of Analysis for the shipment below.</p>
      <table cellspacing="0" cellpadding="6" style="border-collapse:collapse;font-family:Arial,sans-serif;font-size:13px;">
        <tr><td><strong>BOL Number</strong></td><td>${escapeHtml(order.bolNumber || '—')}</td></tr>
        <tr><td><strong>Product</strong></td><td>${escapeHtml(order.product || order.lineItems?.[0]?.productName || '—')}</td></tr>
        <tr><td><strong>Lot #</strong></td><td>${escapeHtml((shipment.lotNumbers || (shipment.lotNumber ? [shipment.lotNumber] : [])).join(', ') || '—')}</td></tr>
        <tr><td><strong>Shipment Date</strong></td><td>${escapeHtml(order.shipmentDate || '—')}</td></tr>
      </table>
      <p>Please review the attached analysis and contact us if you have any questions.</p>
      <p>Thank you,<br/>${escapeHtml(emailSettings.fromName || 'Sucro Canada Quality Assurance')}</p>
    `.trim();

    const result = await runEmailSend({
      type: 'coa',
      orderId: order.id,
      shipmentId: shipment.id,
      customerName: order.customer || '',
      recipientTo,
      subject, html,
      pdfBlob, filename,
      idempotencyRecordId: order.id,
      triggeredBy: opts?.triggeredBy || 'manual',
    });

    if (blobUrl) setTimeout(() => URL.revokeObjectURL(blobUrl), 5000);
    if (!result.success) {
      setErrorBox(`COA email failed: ${result.error || 'Unknown error'} — see Email Center.`);
    }
  };

  const handleGenerateOrderConfirmation = async (order: Order) => {
    setGeneratingOrderConfirmation(order.id);
    try {
      // Renders LITERALLY from the configured "Order Confirmation" Google Sheet
      // template when present; otherwise falls back to the built-in PDF generator.
      const { blob, filename } = await orderConfirmationBlob(order);
      const blobUrl = URL.createObjectURL(blob);
      // Revoke any previous blob URL to prevent memory leaks
      if (pdfPreview?.url) URL.revokeObjectURL(pdfPreview.url);
      setPdfPreview({ url: blobUrl, filename, templateType: 'Order Confirmation' });
    } catch (e: any) {
      console.error('Generate order confirmation failed:', e);
      setErrorBox('Failed to generate order confirmation: ' + (e.message || 'Unknown error'));
    } finally {
      setGeneratingOrderConfirmation(null);
    }
  };

  const handleDownloadPdf = () => {
    if (!pdfPreview) return;
    const link = document.createElement('a');
    link.href = pdfPreview.url;
    link.download = pdfPreview.filename;
    link.click();
  };

  const handleClosePdfPreview = () => {
    if (pdfPreview?.url) URL.revokeObjectURL(pdfPreview.url);
    setPdfPreview(null);
  };

  const handleGenerateBol = (shipment: Shipment) => {
    try {
      const linkedOrder = orders.find(o => o.bolNumber === shipment.bol);
      const cust = customers.find(c => c.name === shipment.customer);
      const carr = carriers.find(c => c.name === shipment.carrier);
      const shipFromLoc = locations.find(l => l.name === (linkedOrder?.location || '') || l.locationCode === (linkedOrder?.location || ''));
      // Resolve ship-to location: order's selection wins; otherwise leave undefined so
      // the BOL falls back to the customer's default address.
      const shipToLoc = linkedOrder?.shipToLocationId
        ? cust?.shipToLocations?.find(l => l.id === linkedOrder.shipToLocationId)
        : undefined;
      const { blobUrl, filename } = generateBolPdf({
        shipment,
        order: linkedOrder,
        customer: cust,
        carrier: carr,
        shipFromLocation: shipFromLoc,
        shipToCustomer: cust,
        shipToLocation: shipToLoc,
        qaProducts,
      });
      if (pdfPreview?.url) URL.revokeObjectURL(pdfPreview.url);
      setPdfPreview({ url: blobUrl, filename, templateType: 'Bill of Lading' });
    } catch (e: any) {
      console.error('Generate BOL failed:', e);
      setErrorBox('Failed to generate Bill of Lading: ' + (e.message || 'Unknown error'));
    }
  };

  const handleGenerateCoa = (shipment: Shipment) => {
    try {
      const linkedOrder = orders.find(o => o.bolNumber === shipment.bol);
      const cust = customers.find(c => c.name === shipment.customer);
      const shipFromLoc = locations.find(l => l.name === (linkedOrder?.location || '') || l.locationCode === (linkedOrder?.location || ''));
      const { blobUrl, filename } = generateCoaPdf({
        shipment,
        order: linkedOrder,
        customer: cust,
        shipFromLocation: shipFromLoc,
        lotCodes,
        qaProducts,
      });
      if (pdfPreview?.url) URL.revokeObjectURL(pdfPreview.url);
      setPdfPreview({ url: blobUrl, filename, templateType: 'Certificate of Analysis' });
    } catch (e: any) {
      console.error('Generate COA failed:', e);
      setErrorBox('Failed to generate Certificate of Analysis: ' + (e.message || 'Unknown error'));
    }
  };

  useEffect(() => {
    if (user) {
      fetchMarketData();
      const interval = setInterval(() => {
        fetchMarketData();
      }, 30 * 60 * 1000);
      return () => clearInterval(interval);
    }
  }, [user]);
  const [showContractConfirm, setShowContractConfirm] = useState(false);
  const [showEmailQuote, setShowEmailQuote] = useState(false);
  const [emailIncludeMargin, setEmailIncludeMargin] = useState(false);
  const [emailTo, setEmailTo] = useState('');
  const [emailCc, setEmailCc] = useState('');
  const [emailSubject, setEmailSubject] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const [sortConfig, setSortConfig] = useState<{ key: string, direction: 'asc' | 'desc' } | null>(null);
  const [orderSortConfig, setOrderSortConfig] = useState<{ key: string, direction: 'asc' | 'desc' }>({ key: 'shipmentDate', direction: 'asc' });
  const [editingSupplyChain, setEditingSupplyChain] = useState<SupplyChainComponent | null>(null);
  const [isAddingSupplyChain, setIsAddingSupplyChain] = useState(false);
  const [editingShipment, setEditingShipment] = useState<Shipment | null>(null);
  const [pendingCompleteOrderId, setPendingCompleteOrderId] = useState<string | null>(null);
  // Confirm + summary popup shown before Complete & Bill actually runs.
  // Holds the order being confirmed; null hides the dialog.
  const [completeAndBillConfirm, setCompleteAndBillConfirm] = useState<Order | null>(null);

  // Return Orders ----------------------------------------------------------
  const [returnOrders, setReturnOrders] = useState<ReturnOrder[]>([]);
  // Persistent dashboard of POs imported from the Gmail inbox scan (Email Center).
  const [poImportLog, setPoImportLog] = useState<PoImportLogEntry[]>([]);
  const [poPendingImports, setPoPendingImports] = useState<PoPendingImport[]>([]);
  const [inboxFeed, setInboxFeed] = useState<InboxFeedItem[]>([]);
  const [inboxTriage, setInboxTriage] = useState<InboxTriage[]>([]);
  // Review queue of emailed order amendments/cancellations (Email Center).
  const [poAmendments, setPoAmendments] = useState<PoAmendment[]>([]);
  // Add / Edit modal state. When isAddingReturnOrder is true the modal opens
  // in "add" mode; when editingReturnOrder is non-null it opens in edit mode.
  const [isAddingReturnOrder, setIsAddingReturnOrder] = useState(false);
  const [editingReturnOrder, setEditingReturnOrder] = useState<ReturnOrder | null>(null);
  // Buffer used by the add/edit modal — populated when the user picks a
  // source BOL from the search list. We snapshot the invoice/order line
  // items so subsequent line-item edits don't ripple back into source data.
  const [returnOrderDraft, setReturnOrderDraft] = useState<ReturnOrder | null>(null);
  // Free-text BOL/customer/product search inside the add modal.
  const [returnOrderBolSearch, setReturnOrderBolSearch] = useState('');
  // Confirm dialog for Return & Bill — same pattern as Complete & Bill.
  const [returnAndBillConfirm, setReturnAndBillConfirm] = useState<ReturnOrder | null>(null);
  // PDF preview state for return-order confirmation document.
  const [viewingReturnOrderCard, setViewingReturnOrderCard] = useState<ReturnOrder | null>(null);
  const [editingCarrier, setEditingCarrier] = useState<Carrier | null>(null);
  const [isAddingShipment, setIsAddingShipment] = useState(false);
  const [editingAppointmentSchedule, setEditingAppointmentSchedule] = useState<Location | null>(null);
  const [newSupplyChain, setNewSupplyChain] = useState<SupplyChainComponent>({
    id: '',
    component: '',
    provider: '',
    totalCostCad: 0,
    weightPerLoadMt: 1
  });

  // Track last synced data to avoid redundant syncs
  const lastSyncedData = useRef<Record<string, string>>({
    customers: JSON.stringify(INITIAL_CUSTOMERS),
    products: JSON.stringify(INITIAL_SKUS),
    logistics: JSON.stringify(INITIAL_SUPPLY_CHAIN),
    freightrates: JSON.stringify(INITIAL_FREIGHT_RATES),
    contracts: JSON.stringify(INITIAL_CONTRACTS),
    carriers: JSON.stringify(INITIAL_CARRIERS),
    shipments: JSON.stringify([]),
    locations: JSON.stringify(INITIAL_LOCATIONS),
    transfers: JSON.stringify([]),
    invoices: JSON.stringify([]),
    orders: JSON.stringify([]),
    productgroups: JSON.stringify(INITIAL_PRODUCT_GROUPS),
    conferences: JSON.stringify([]),
    people: JSON.stringify(INITIAL_PEOPLE),
    qaproducts: JSON.stringify([]),
    fuelsurcharges: JSON.stringify([]),
    vendors: JSON.stringify([]),
    cheppalletmovements: JSON.stringify([]),
    salesleads: JSON.stringify([]),
    qatemplates: JSON.stringify([]),
    customergroups: JSON.stringify([]),
    shippingterms: JSON.stringify(INITIAL_SHIPPING_TERMS),
    emaillog: JSON.stringify([]),
    emailsettings: JSON.stringify([INITIAL_EMAIL_SETTINGS]),
    returnorders: JSON.stringify([]),
    poimportlog: JSON.stringify([]),
    poamendments: JSON.stringify([]),
  });

  // Fetch initial data from Firestore
  const loadDataFromFirestore = async () => {
    try {
      setSyncStatus('syncing');
      setSyncError(null);
      const data = await fetchAllData();

      // Authoritative: reflect Firestore even when a collection comes back EMPTY,
      // so the built-in demo customers/products can never linger in state and then
      // be persisted over the real records. A failed read throws and aborts the
      // whole load (autosave stays disabled), so an empty array here means the
      // collection genuinely is empty — not a glitch.
      if (data.customers) {
        const mapped = data.customers.map((c: any) => ({
          ...c,
          defaultMargin: parseFloat(c.defaultMargin) || 0
        }));
        setCustomers(mapped);
        lastSyncedData.current.customers = JSON.stringify(mapped);
      }
      if (data.products) {
        const validLocations = ['Hamilton', 'Vancouver'];
        const mapped = data.products.map((s: any) => ({
          ...s,
          productGroup: s.productGroup || s.productType || 'Bulk',
          netWeight: parseFloat(s.netWeight) || 0,
          brix: parseFloat(s.brix) || 0,
          premiumCadMt: parseFloat(s.premiumCadMt) || 0,
          netWeightKg: s.netWeightKg ? (parseFloat(s.netWeightKg) || 0) : (s.unitSizeKg ? (parseFloat(s.unitSizeKg) || 0) : undefined),
          grossWeightKg: s.grossWeightKg ? (parseFloat(s.grossWeightKg) || 0) : undefined,
          location: validLocations.includes(s.location) ? s.location : 'Hamilton',
          category: (s.category === 'Conventional' || s.category === 'Organic') ? s.category : 'Conventional'
        }));
        setSkus(mapped);
        lastSyncedData.current.products = JSON.stringify(mapped);
      }
      if (data.logistics?.length) {
        const mapped = data.logistics.map((l: any) => ({
          ...l,
          totalCostCad: parseFloat(l.totalCostCad) || 0,
          weightPerLoadMt: parseFloat(l.weightPerLoadMt) || 0
        }));
        setSupplyChain(mapped);
        lastSyncedData.current.logistics = JSON.stringify(mapped);
      }
      if (data.freightRates?.length) {
        const validTypes = ['Dry Van', 'Bulk', 'Liquid', 'Bulk Rail', 'Intermodal'];
        const mapped = data.freightRates.map((f: any) => ({
          ...f,
          cost: parseFloat(f.cost) || 0,
          mtPerLoad: parseFloat(f.mtPerLoad) || 0,
          freightType: validTypes.includes(f.freightType) ? f.freightType : 'Dry Van'
        }));
        setFreightRates(mapped);
        lastSyncedData.current.freightrates = JSON.stringify(mapped);
      }
      if (data.contracts?.length) {
        const mapped = data.contracts.map((c: any) => {
          const contractVolume = parseFloat(c.contractVolume) || 0;
          const volumeTaken = parseFloat(c.volumeTaken) || 0;
          return {
            ...c,
            contractVolume,
            volumeTaken,
            volumeOutstanding: parseFloat(c.volumeOutstanding) || (contractVolume - volumeTaken),
            finalPrice: parseFloat(c.finalPrice) || 0,
            active: c.active !== false ? true : false
          };
        });
        setContracts(mapped);
        lastSyncedData.current.contracts = JSON.stringify(mapped);
      }
      if (data.carriers?.length) {
        setCarriers(data.carriers);
        lastSyncedData.current.carriers = JSON.stringify(data.carriers);
      }
      if (data.shipments?.length) {
        const mapped = data.shipments.map((s: any) => ({
          ...s,
          qty: parseFloat(s.qty) || 0
        }));
        // Split shipments by location using bay names from location data
        const locs = data.locations?.length ? data.locations : [];
        const vancLoc = locs.find((l: any) => l.name?.toLowerCase().includes('vancouver'));
        const vancBays: string[] = vancLoc
          ? (typeof vancLoc.bays === 'string' ? vancLoc.bays.split(',').map((b: string) => b.trim()) : (vancLoc.bays || []))
          : [];
        const vancouver = mapped.filter((s: any) => vancBays.some((b: string) => s.bay === b));
        const hamilton = mapped.filter((s: any) => !vancBays.some((b: string) => s.bay === b));
        // Deduplicate: one shipment per week+day+time+bay, keep first occurrence
        const dedup = (arr: Shipment[]) => {
          const seen = new Set<string>();
          return arr.filter(s => {
            const key = `${s.week}|${s.day}|${s.time}|${s.bay}`;
            if (seen.has(key)) return false;
            seen.add(key);
            return true;
          });
        };
        const dedupHamilton = dedup(hamilton);
        const dedupVancouver = dedup(vancouver);
        const totalRemoved = (hamilton.length - dedupHamilton.length) + (vancouver.length - dedupVancouver.length);
        setHamiltonShipments(dedupHamilton);
        setVancouverShipments(dedupVancouver);
        const dedupAll = [...dedupHamilton, ...dedupVancouver];
        // If duplicates were removed, sync cleaned data to Firebase
        if (totalRemoved > 0) {
          console.log(`Removed ${totalRemoved} duplicate shipment(s)`);
          syncCollection(COLLECTIONS.shipments, dedupAll).then(() => {
            lastSyncedData.current.shipments = JSON.stringify(dedupAll);
            setSyncStatus('synced');
            setLastSynced(new Date());
          }).catch(e => console.error('Shipment dedup sync failed:', e));
        }
        lastSyncedData.current.shipments = JSON.stringify(dedupAll);
      }
      if (data.locations?.length) {
        const mapped = data.locations.map((l: any, idx: number) => ({
          ...l,
          locationCode: l.locationCode || String((idx + 1) * 100),
          bays: Array.isArray(l.bays) ? l.bays : (typeof l.bays === 'string' ? l.bays.split(',').map((b: string) => b.trim()).filter(Boolean) : []),
          appointmentStartTime: l.appointmentStartTime || '06:00',
          appointmentEndTime: l.appointmentEndTime || '18:00',
          appointmentDuration: l.appointmentDuration || 30
        }));
        setLocations(mapped);
        lastSyncedData.current.locations = JSON.stringify(mapped);
      }
      if (data.transfers?.length) {
        const mapped = data.transfers.map((t: any) => ({
          ...t,
          amount: parseFloat(t.amount) || 0,
          legs: Array.isArray(t.legs) ? t.legs.map((leg: any) => ({ ...leg, amount: parseFloat(leg.amount) || 0 })) : undefined
        }));
        setTransfers(mapped);
        lastSyncedData.current.transfers = JSON.stringify(mapped);
      }
      if (data.invoices?.length) {
        const mapped = data.invoices.map((i: any) => ({
          ...i,
          qty: parseFloat(i.qty) || 0,
          amount: parseFloat(i.amount) || 0
        }));

        const uniqueInvoices: Invoice[] = [];
        const seenShipmentIds = new Set<string>();
        for (const inv of mapped) {
          if (inv.shipmentId && seenShipmentIds.has(inv.shipmentId)) continue;
          if (inv.shipmentId) seenShipmentIds.add(inv.shipmentId);
          uniqueInvoices.push(inv);
        }

        setInvoices(uniqueInvoices);
        lastSyncedData.current.invoices = JSON.stringify(uniqueInvoices);
      }
      if (data.productGroups?.length) {
        setProductGroups(data.productGroups);
        lastSyncedData.current.productgroups = JSON.stringify(data.productGroups);
      }
      if (data.orders?.length) {
        const mapped = data.orders.map((o: any) => ({
          ...o,
          amount: parseFloat(o.amount) || 0,
          lineItems: Array.isArray(o.lineItems) ? o.lineItems : (typeof o.lineItems === 'string' ? JSON.parse(o.lineItems) : [])
        }));
        setOrders(mapped);
        lastSyncedData.current.orders = JSON.stringify(mapped);
      }
      if (data.conferences?.length) {
        // Normalize conference meetings to ensure customerAttendeeDetails is always an array
        const normalizedConferences = data.conferences.map((conf: any) => ({
          ...conf,
          meetings: Array.isArray(conf.meetings) ? conf.meetings.map((m: any) => ({
            ...m,
            customerAttendeeDetails: Array.isArray(m.customerAttendeeDetails) ? m.customerAttendeeDetails : [],
            customerAttendees: Array.isArray(m.customerAttendees) ? m.customerAttendees : [],
            attendees: Array.isArray(m.attendees) ? m.attendees : [],
            followUps: Array.isArray(m.followUps) ? m.followUps : [],
          })) : [],
        }));
        setConferences(normalizedConferences);
        lastSyncedData.current.conferences = JSON.stringify(normalizedConferences);
      }
      if (data.people?.length) {
        setPeople(data.people);
        lastSyncedData.current.people = JSON.stringify(data.people);
      }
      if (data.qaProducts?.length) {
        const mapped = data.qaProducts.map((qa: any) => ({
          ...qa,
          specifications: qa.specifications || { brix: '', granulation: '', color: '', ash: '', turbidity: '', moisture: '' },
          packagingPictureUrls: qa.packagingPictureUrls || [],
          packagingPictureFilenames: qa.packagingPictureFilenames || [],
          artworkApprovals: qa.artworkApprovals || [],
          specSheets: qa.specSheets || [],
          certificates: qa.certificates || [],
        }));
        setQaProducts(mapped);
        lastSyncedData.current.qaproducts = JSON.stringify(mapped);
      }
      if (data.fuelSurcharges?.length) {
        setFuelSurcharges(data.fuelSurcharges);
        lastSyncedData.current.fuelsurcharges = JSON.stringify(data.fuelSurcharges);
      }
      if (data.tollingFees?.length) {
        setTollingFees(data.tollingFees as TollingFee[]);
        lastSyncedData.current.tollingfees = JSON.stringify(data.tollingFees);
      }
      if (data.vendors?.length) {
        setVendors(data.vendors);
        lastSyncedData.current.vendors = JSON.stringify(data.vendors);
      }
      if (data.chepPalletMovements?.length) {
        setChepPalletMovements(data.chepPalletMovements);
        lastSyncedData.current.cheppalletmovements = JSON.stringify(data.chepPalletMovements);
      }
      if (data.salesLeads?.length) {
        setSalesLeads(data.salesLeads);
        lastSyncedData.current.salesleads = JSON.stringify(data.salesLeads);
      }
      if (data.sampleRequests?.length) {
        setSampleRequests(data.sampleRequests);
        lastSyncedData.current.samplerequests = JSON.stringify(data.sampleRequests);
      }
      if (data.qaTemplates?.length) {
        setQaTemplates(data.qaTemplates);
        lastSyncedData.current.qatemplates = JSON.stringify(data.qaTemplates);
      }
      if (data.sugarTypes?.length) {
        setSugarTypes(data.sugarTypes);
        lastSyncedData.current.sugartypes = JSON.stringify(data.sugarTypes);
      }
      if (data.lotCodes?.length) {
        setLotCodes(data.lotCodes);
        lastSyncedData.current.lotcodes = JSON.stringify(data.lotCodes);
      }
      if (data.fiscalYears?.length) {
        setFiscalYears(data.fiscalYears);
        lastSyncedData.current.fiscalyears = JSON.stringify(data.fiscalYears);
      }
      if (data.customerForecasts?.length) {
        setCustomerForecasts(data.customerForecasts);
        lastSyncedData.current.customerforecasts = JSON.stringify(data.customerForecasts);
      }
      if (data.customerGroups?.length) {
        setCustomerGroups(data.customerGroups);
        lastSyncedData.current.customergroups = JSON.stringify(data.customerGroups);
      }
      if (data.packagingFormats?.length) {
        setPackagingFormats(data.packagingFormats);
        lastSyncedData.current.packagingformats = JSON.stringify(data.packagingFormats);
      }
      if (data.namingFormulas?.length) {
        // Normalize: ensure tokens array exists (may be undefined for legacy rows)
        // Also migrate legacy 'Long Form' type to 'Product Name'
        const mapped = data.namingFormulas.map((nf: any) => ({
          ...nf,
          type: nf.type === 'Long Form' ? 'Product Name' : nf.type,
          priority: typeof nf.priority === 'number' ? nf.priority : parseInt(nf.priority) || 50,
          tokens: Array.isArray(nf.tokens) ? nf.tokens : undefined,
        }));
        setNamingFormulas(mapped);
        lastSyncedData.current.namingformulas = JSON.stringify(mapped);
      }
      if (data.shippingTerms?.length) {
        setShippingTermsList(data.shippingTerms as ShippingTerm[]);
        lastSyncedData.current.shippingterms = JSON.stringify(data.shippingTerms);
      }
      if (data.emailLog?.length) {
        setEmailLog(data.emailLog as EmailLog[]);
        lastSyncedData.current.emaillog = JSON.stringify(data.emailLog);
      }
      if (data.emailSettings?.length) {
        const settings = (data.emailSettings as EmailSettings[]).find(s => s.id === 'settings') || data.emailSettings[0] as EmailSettings;
        setEmailSettings({ ...INITIAL_EMAIL_SETTINGS, ...settings });
        lastSyncedData.current.emailsettings = JSON.stringify([settings]);
      }
      if (data.returnOrders?.length) {
        setReturnOrders(data.returnOrders as ReturnOrder[]);
        lastSyncedData.current.returnorders = JSON.stringify(data.returnOrders);
      }
      if (data.poImportLog?.length) {
        setPoImportLog(data.poImportLog as PoImportLogEntry[]);
        lastSyncedData.current.poimportlog = JSON.stringify(data.poImportLog);
      }
      if (data.poPendingImports?.length) {
        setPoPendingImports(data.poPendingImports as PoPendingImport[]);
        lastSyncedData.current.popendingimports = JSON.stringify(data.poPendingImports);
      }
      if (data.inboxTriage?.length) {
        setInboxTriage(data.inboxTriage as InboxTriage[]);
        lastSyncedData.current.inboxtriage = JSON.stringify(data.inboxTriage);
      }
      if (data.inboxFeed?.length) {
        setInboxFeed(data.inboxFeed as InboxFeedItem[]);
      }
      if (data.poAmendments?.length) {
        setPoAmendments(data.poAmendments as PoAmendment[]);
        lastSyncedData.current.poamendments = JSON.stringify(data.poAmendments);
      }
      {
        // Merge synced learned corrections with any local (unsynced) ones, drop
        // any older than 30 days, then persist the cleaned union to localStorage.
        // Pruning here + the whole-collection autosave below physically deletes
        // expired mappings from Firestore the next time the app loads.
        const remoteLearned = (data.poFieldMappings as LearnedMapping[]) || [];
        const merged = pruneExpired(mergeLearned(remoteLearned, loadLearned()));
        setPoLearned(merged);
        saveLearned(merged);
        if (remoteLearned.length) lastSyncedData.current.pofieldmappings = JSON.stringify(data.poFieldMappings);
      }
      if (data.MarketData?.length) {
        setMarketData(data.MarketData);
        setLastMarketUpdate(new Date().toISOString());
        const months = Array.from(new Set(data.MarketData.map((d: any) => d.Month || d.month).filter(Boolean))) as string[];
        if (months.length > 0) {
          setConfig(prev => {
            const isIsoDate = (val: string | undefined) => val && /^\d{4}-\d{2}-\d{2}$/.test(val);
            return {
              ...prev,
              contractStartDate: (!prev.contractStartDate || isIsoDate(prev.contractStartDate)) ? months[0] : prev.contractStartDate,
              contractEndDate: (!prev.contractEndDate || isIsoDate(prev.contractEndDate)) ? months[Math.min(months.length - 1, 3)] : prev.contractEndDate
            };
          });
        }
      }

      setSyncStatus('synced');
      setLastSynced(new Date());
    } catch (e) {
      console.error("Failed to fetch data:", e);
      setSyncStatus('error');
      setSyncError((e as Error).message);
    }
  };

  useEffect(() => {
    if (user) {
      loadDataFromFirestore();
    }
  }, [user]);

  // Sync data to Firestore with debounce
  const isSyncing = useRef(false);
  useEffect(() => {
    const syncAll = async () => {
      if (isSyncing.current || !lastSynced || !user) return;
      isSyncing.current = true;

      const syncTasks: { collection: string; key: string; data: any[]; allowMassDelete?: boolean }[] = [
        { collection: COLLECTIONS.customers, key: 'customers', data: customers },
        { collection: COLLECTIONS.products, key: 'products', data: skus },
        { collection: COLLECTIONS.logistics, key: 'logistics', data: supplyChain },
        { collection: COLLECTIONS.freightRates, key: 'freightrates', data: freightRates },
        { collection: COLLECTIONS.contracts, key: 'contracts', data: contracts },
        { collection: COLLECTIONS.carriers, key: 'carriers', data: carriers },
        { collection: COLLECTIONS.shipments, key: 'shipments', data: [...hamiltonShipments, ...vancouverShipments] },
        { collection: COLLECTIONS.locations, key: 'locations', data: locations },
        { collection: COLLECTIONS.transfers, key: 'transfers', data: transfers },
        { collection: COLLECTIONS.invoices, key: 'invoices', data: invoices },
        { collection: COLLECTIONS.productGroups, key: 'productgroups', data: productGroups },
        { collection: COLLECTIONS.orders, key: 'orders', data: orders },
        { collection: COLLECTIONS.conferences, key: 'conferences', data: conferences },
        { collection: COLLECTIONS.people, key: 'people', data: people },
        { collection: COLLECTIONS.qaProducts, key: 'qaproducts', data: qaProducts },
        { collection: COLLECTIONS.fuelSurcharges, key: 'fuelsurcharges', data: fuelSurcharges },
        { collection: COLLECTIONS.tollingFees, key: 'tollingfees', data: tollingFees },
        { collection: COLLECTIONS.vendors, key: 'vendors', data: vendors },
        { collection: COLLECTIONS.chepPalletMovements, key: 'cheppalletmovements', data: chepPalletMovements },
        { collection: COLLECTIONS.salesLeads, key: 'salesleads', data: salesLeads },
        { collection: COLLECTIONS.sampleRequests, key: 'samplerequests', data: sampleRequests },
        { collection: COLLECTIONS.qaTemplates, key: 'qatemplates', data: qaTemplates },
        { collection: COLLECTIONS.sugarTypes, key: 'sugartypes', data: sugarTypes },
        { collection: COLLECTIONS.lotCodes, key: 'lotcodes', data: lotCodes },
        { collection: COLLECTIONS.fiscalYears, key: 'fiscalyears', data: fiscalYears },
        { collection: COLLECTIONS.customerForecasts, key: 'customerforecasts', data: customerForecasts },
        { collection: COLLECTIONS.customerGroups, key: 'customergroups', data: customerGroups },
        { collection: COLLECTIONS.packagingFormats, key: 'packagingformats', data: packagingFormats },
        { collection: COLLECTIONS.namingFormulas, key: 'namingformulas', data: namingFormulas },
        { collection: COLLECTIONS.shippingTerms, key: 'shippingterms', data: shippingTermsList },
        // Review queues + logs: emptying / clearing them is a normal operator
        // action, so they bypass the mass-deletion guard (a dismissed / approved
        // PO or amendment must stay gone after a refresh).
        { collection: COLLECTIONS.emailLog,      key: 'emaillog',      data: emailLog, allowMassDelete: true },
        { collection: COLLECTIONS.emailSettings, key: 'emailsettings', data: [emailSettings] },
        { collection: COLLECTIONS.returnOrders,  key: 'returnorders',  data: returnOrders },
        { collection: COLLECTIONS.poImportLog,   key: 'poimportlog',   data: poImportLog, allowMassDelete: true },
        { collection: COLLECTIONS.poPendingImports, key: 'popendingimports', data: poPendingImports, allowMassDelete: true },
        { collection: COLLECTIONS.inboxTriage, key: 'inboxtriage', data: inboxTriage, allowMassDelete: true },
        { collection: COLLECTIONS.poAmendments,  key: 'poamendments',  data: poAmendments, allowMassDelete: true },
        { collection: COLLECTIONS.poFieldMappings, key: 'pofieldmappings', data: pruneExpired(poLearned).map(l => ({ id: learnedId(l), ...l })), allowMassDelete: true },
      ];

      try {
        for (const task of syncTasks) {
          const dataStr = JSON.stringify(task.data);
          if (dataStr === lastSyncedData.current[task.key]) continue;

          setSyncStatus('syncing');
          await syncCollection(task.collection, task.data, { allowMassDelete: task.allowMassDelete });
          lastSyncedData.current[task.key] = dataStr;
        }

        setSyncStatus('synced');
        setLastSynced(new Date());
        setSyncError(null);
      } catch (e) {
        setSyncStatus('error');
        setSyncError((e as Error).message);
      } finally {
        isSyncing.current = false;
      }
    };

    const timeout = setTimeout(syncAll, 15000);
    return () => clearTimeout(timeout);
  }, [customers, skus, supplyChain, freightRates, contracts, carriers, hamiltonShipments, vancouverShipments, locations, transfers, invoices, productGroups, orders, conferences, people, qaProducts, fuelSurcharges, tollingFees, vendors, chepPalletMovements, salesLeads, sampleRequests, qaTemplates, sugarTypes, lotCodes, customerGroups, packagingFormats, namingFormulas, shippingTermsList, emailLog, emailSettings, returnOrders, poImportLog, poPendingImports, inboxTriage, poAmendments, poLearned, lastSynced, user]);

  // Fast-persist the review queues so a dismissed / approved PO or amendment
  // sticks immediately and never reappears on a quick refresh. The main autosave
  // is debounced 15s; this mirrors just these two queues within ~0.6s and bypasses
  // the mass-deletion guard (clearing a queue is a normal operator action).
  useEffect(() => {
    if (!user || !lastSynced) return;
    const t = setTimeout(() => {
      const quick: { c: string; k: string; d: any[] }[] = [
        { c: COLLECTIONS.poPendingImports, k: 'popendingimports', d: poPendingImports },
        { c: COLLECTIONS.poAmendments, k: 'poamendments', d: poAmendments },
      ];
      quick.forEach(({ c, k, d }) => {
        const s = JSON.stringify(d);
        if (s === lastSyncedData.current[k]) return;
        syncCollection(c, d, { allowMassDelete: true })
          .then(() => { lastSyncedData.current[k] = s; })
          .catch(e => console.error('queue persist failed:', c, e));
      });
    }, 600);
    return () => clearTimeout(t);
  }, [poPendingImports, poAmendments, user, lastSynced]);

  // Poll the incomingPoOrders queue (filled by the Gmail PO scan cron) and
  // ingest any new POs as Open orders: shortly after login, then every 5 min.
  useEffect(() => {
    if (!user) return;
    const t = setTimeout(() => { ingestPOsRef.current(); loadInboxFeed(); }, 8000);
    const interval = setInterval(() => { ingestPOsRef.current(); loadInboxFeed(); }, 5 * 60 * 1000);
    return () => { clearTimeout(t); clearInterval(interval); };
  }, [user]);

  // One-time backfill: assign a uniform 6-digit productCode to every SKU and
  // mirror it onto every matching QAProduct. Existing codes are preserved.
  const productCodeBackfillRan = useRef(false);
  useEffect(() => {
    if (productCodeBackfillRan.current) return;
    if (skus.length === 0 && qaProducts.length === 0) return;

    // Collect existing codes so we don't re-use one
    const used = new Set<string>();
    skus.forEach(s => { if (s.productCode) used.add(s.productCode); });
    qaProducts.forEach(q => { if (q.productCode) used.add(q.productCode); });

    let next = 1;
    // Seed counter at the highest numeric code already in use
    used.forEach(c => {
      const n = parseInt(c, 10);
      if (!isNaN(n) && n >= next) next = n + 1;
    });
    const nextCode = (): string => {
      let candidate = String(next).padStart(6, '0');
      while (used.has(candidate)) {
        next++;
        candidate = String(next).padStart(6, '0');
      }
      used.add(candidate);
      next++;
      return candidate;
    };

    // Assign to SKUs missing a code (sorted by id for stable ordering)
    const skuUpdates = new Map<string, string>();
    [...skus].sort((a, b) => (a.id || '').localeCompare(b.id || '')).forEach(s => {
      if (!s.productCode) skuUpdates.set(s.id, nextCode());
    });

    // Build skuId -> productCode lookup (existing + new) for QA mirror
    const skuCodeLookup = new Map<string, string>();
    skus.forEach(s => {
      const code = skuUpdates.get(s.id) || s.productCode;
      if (code) skuCodeLookup.set(s.id, code);
    });

    // Assign to QA products: mirror SKU's code; otherwise generate new
    const qaUpdates = new Map<string, string>();
    qaProducts.forEach(q => {
      if (q.productCode) return; // already set
      const mirrored = skuCodeLookup.get(q.skuId);
      if (mirrored) qaUpdates.set(q.id, mirrored);
      else qaUpdates.set(q.id, nextCode());
    });

    if (skuUpdates.size === 0 && qaUpdates.size === 0) {
      productCodeBackfillRan.current = true;
      return;
    }

    if (skuUpdates.size > 0) {
      setSkus(prev => prev.map(s => skuUpdates.has(s.id) ? { ...s, productCode: skuUpdates.get(s.id) } : s));
    }
    if (qaUpdates.size > 0) {
      setQaProducts(prev => prev.map(q => qaUpdates.has(q.id) ? { ...q, productCode: qaUpdates.get(q.id) } : q));
    }
    productCodeBackfillRan.current = true;
  }, [skus, qaProducts]);

  // One-time backfill: regenerate BOL numbers for orders that don't match the
  // canonical format (single letter + 6 digits). The counter starts from the
  // max BOL counter already present in both the orders and invoices tables,
  // so new sequence numbers never collide with anything in invoices.
  const bolBackfillRan = useRef(false);
  useEffect(() => {
    if (bolBackfillRan.current) return;
    if (orders.length === 0) return;
    if (productGroups.length === 0 || skus.length === 0) return; // need catalog to pick prefix

    // Only backfill orders whose BOL is EMPTY. Previously this checked
    // /^[A-Z]\d{6}$/ ("canonical") and rewrote anything else — that was the
    // cause of "phantom" P0000XX orders: imported BOLs like L2054980 (LIQ)
    // or B304582 (DRY) don't match the canonical shape, so they were getting
    // renamed away from the value in the source sheet. Imported BOLs are
    // authoritative; only blank ones get an auto-assigned sequence number.
    const hasBol = (bol: string | undefined) => !!bol && bol.trim().length > 0;
    const ordersNeedingBol = orders.filter(o => !hasBol(o.bolNumber));
    if (ordersNeedingBol.length === 0) {
      bolBackfillRan.current = true;
      return;
    }

    // Determine prefix for an order from its line items' product group BOL Codes
    // (robust resolve via productKey, then name). Single group → that code;
    // mixed → the first line item's code.
    const prefixForOrder = (o: Order): string => {
      const items = o.lineItems || [];
      const groups = items.map(li => productGroupOf(li.productName, li.productKey) || 'Other');
      const unique = new Set(groups);
      if (unique.size === 1) return bolPrefixForGroup([...unique][0]);
      if (items.length > 0) return bolPrefixForGroup(productGroupOf(items[0].productName, items[0].productKey));
      return 'P';
    };

    // Build a per-prefix counter that starts at the current max in BOTH orders and invoices
    const counterByPrefix = new Map<string, number>();
    const usedBols = new Set<string>();
    const extract = (bol: string | undefined): { prefix: string; n: number } | null => {
      if (!bol) return null;
      const canon = bol.match(/^([A-Z])(\d{6})$/);
      if (canon) return { prefix: canon[1], n: parseInt(canon[2], 10) };
      const dash = bol.match(/^([A-Z])-\d+-(\d+)$/);
      if (dash) return { prefix: dash[1], n: parseInt(dash[2], 10) };
      return null;
    };
    const seed = (bol: string | undefined) => {
      if (!bol) return;
      usedBols.add(bol);
      const p = extract(bol);
      if (!p) return;
      const cur = counterByPrefix.get(p.prefix) || 0;
      if (p.n > cur) counterByPrefix.set(p.prefix, p.n);
    };
    orders.forEach(o => seed(o.bolNumber));
    invoices.forEach(i => seed(i.bolNumber));

    const nextBol = (prefix: string): string => {
      let n = (counterByPrefix.get(prefix) || 0) + 1;
      let candidate = `${prefix}${String(n).padStart(6, '0')}`;
      while (usedBols.has(candidate)) {
        n++;
        candidate = `${prefix}${String(n).padStart(6, '0')}`;
      }
      counterByPrefix.set(prefix, n);
      usedBols.add(candidate);
      return candidate;
    };

    // Assign new BOLs (sorted by creation date, oldest first, to keep order intuitive)
    const sorted = [...ordersNeedingBol].sort((a, b) => (a.date || '').localeCompare(b.date || ''));
    const remap = new Map<string, string>(); // orderId -> newBol
    sorted.forEach(o => {
      const newBol = nextBol(prefixForOrder(o));
      remap.set(o.id, newBol);
    });

    setOrders(prev => prev.map(o => remap.has(o.id) ? { ...o, bolNumber: remap.get(o.id)! } : o));
    bolBackfillRan.current = true;
  }, [orders, invoices, productGroups, skus]);

  // Auto-fill contract ↔ ITAS Name + Customer fields.
  //   ITAS → Customer:
  //     - Strongest signal: customer.itasCustomerName === contract.itasName.
  //     - Otherwise strip a trailing ".X" suffix from the ITAS name and look
  //       for a customer whose name matches (case-insensitive).
  //         "Lalle.P"   → "Lalle"   → customer "Lalle"
  //         "LECLERC.P" → "LECLERC" → customer "Leclerc"
  //   Customer → ITAS:
  //     - When the contract has a customer link but no itasName, copy
  //       customer.itasCustomerName onto the contract.
  // Only BLANK fields are filled; user-entered values are never overwritten.
  // The effect is idempotent — once every contract is filled, it short-circuits.
  useEffect(() => {
    if (contracts.length === 0 || customers.length === 0) return;

    const itasToCustomerKey = (itas: string | undefined): string => {
      if (!itas) return '';
      // Strip a trailing dot + 1-3 letters ("Lalle.P" → "Lalle").
      const stripped = itas.replace(/\.[A-Za-z]{1,4}$/, '');
      return stripped.trim().toLowerCase();
    };

    const findCustomerForItas = (itas: string): Customer | null => {
      if (!itas) return null;
      const itasNorm = itas.trim().toLowerCase();
      // Direction A: exact itasCustomerName match — strongest signal.
      const byItasField = customers.find(c => (c.itasCustomerName || '').trim().toLowerCase() === itasNorm);
      if (byItasField) return byItasField;
      // Direction B: name match against the stripped key.
      const key = itasToCustomerKey(itas);
      if (!key) return null;
      return customers.find(c => (c.name || '').trim().toLowerCase() === key) || null;
    };

    const findCustomerForContract = (c: Contract): Customer | null => {
      const byName = (c.customerName || '').trim().toLowerCase();
      const byNumber = (c.customerNumber || '').trim();
      if (byName) {
        const match = customers.find(cust => (cust.name || '').trim().toLowerCase() === byName);
        if (match) return match;
      }
      if (byNumber) {
        const match = customers.find(cust => cust.customerNumber === byNumber || cust.id === byNumber);
        if (match) return match;
      }
      return null;
    };

    let changed = false;
    const updated = contracts.map(c => {
      const patch: Partial<Contract> = {};

      // Direction 1: ITAS → Customer (fill blank customerName / customerNumber)
      if (c.itasName && (!c.customerName || !c.customerNumber)) {
        const matched = findCustomerForItas(c.itasName);
        if (matched) {
          if (!c.customerName) patch.customerName = matched.name;
          if (!c.customerNumber) patch.customerNumber = matched.customerNumber || matched.id;
        }
      }

      // Direction 2: Customer → ITAS (fill blank itasName)
      if (!c.itasName && (c.customerName || c.customerNumber)) {
        const matched = findCustomerForContract(c);
        if (matched?.itasCustomerName) {
          patch.itasName = matched.itasCustomerName;
        }
      }

      if (Object.keys(patch).length === 0) return c;
      changed = true;
      return { ...c, ...patch };
    });

    if (changed) setContracts(updated);
  }, [contracts, customers]);

  // Auto-fill missing shipment fields from matching orders by BOL number
  const shipmentAutoFillRan = useRef(false);
  useEffect(() => {
    if (shipmentAutoFillRan.current) return;
    if (orders.length === 0 || (hamiltonShipments.length === 0 && vancouverShipments.length === 0)) return;
    shipmentAutoFillRan.current = true;

    const fillFromOrders = (shipments: Shipment[]): { updated: Shipment[]; count: number } => {
      let count = 0;
      const updated = shipments.map(s => {
        if (!s.bol) return s;
        const order = orders.find(o => o.bolNumber === s.bol);
        if (!order) return s;
        const li = order.lineItems[0];
        const needsFill =
          !s.contractNumber || !s.customer || !s.product || !s.po || !s.carrier || !s.deliveryDate;
        if (!needsFill) return s;
        count++;
        return {
          ...s,
          contractNumber: s.contractNumber || li?.contractNumber || order.contractNumber || s.contractNumber,
          customer: s.customer || order.customer,
          product: s.product || (li?.productName || order.product),
          po: s.po || order.po,
          carrier: s.carrier || order.carrier,
          deliveryDate: s.deliveryDate || order.deliveryDate,
        };
      });
      return { updated, count };
    };

    const ham = fillFromOrders(hamiltonShipments);
    const van = fillFromOrders(vancouverShipments);
    const totalFilled = ham.count + van.count;

    if (totalFilled > 0) {
      console.log(`Auto-filled ${totalFilled} shipment(s) from order data`);
      if (ham.count > 0) setHamiltonShipments(ham.updated);
      if (van.count > 0) setVancouverShipments(van.updated);
    }
  }, [orders, hamiltonShipments, vancouverShipments]);

  // Sync QA product edits back to the Products (SKU) table
  // Updates existing SKUs and creates new ones for QA products with no match
  useEffect(() => {
    if (qaProducts.length === 0) return;
    let changed = false;

    // Update existing SKUs that have a matching QA product
    const updatedSkus = skus.map(sku => {
      const qa = qaProducts.find(q => q.skuId === sku.id);
      if (!qa) return sku;
      if (
        qa.skuName !== sku.name ||
        qa.productGroup !== sku.productGroup ||
        qa.category !== sku.category ||
        qa.location !== sku.location ||
        (qa.netWeightKg !== undefined && qa.netWeightKg !== (sku.netWeightKg || sku.netWeight)) ||
        (qa.grossWeightKg !== undefined && qa.grossWeightKg !== sku.grossWeightKg) ||
        qa.maxColor !== sku.maxColor
      ) {
        changed = true;
        return {
          ...sku,
          name: qa.skuName,
          productGroup: qa.productGroup,
          category: qa.category,
          location: qa.location,
          netWeightKg: qa.netWeightKg ?? sku.netWeightKg ?? sku.netWeight,
          netWeight: qa.netWeightKg ?? sku.netWeightKg ?? sku.netWeight,
          grossWeightKg: qa.grossWeightKg ?? sku.grossWeightKg,
          maxColor: qa.maxColor,
        };
      }
      return sku;
    });

    // Create new SKUs for QA products that have no matching SKU
    const newSkus: SKU[] = [];
    qaProducts.forEach(qa => {
      if (!qa.skuName.trim()) return; // skip blank names
      const existingSku = updatedSkus.find(s => s.id === qa.skuId);
      if (!existingSku) {
        newSkus.push({
          id: qa.skuId,
          name: qa.skuName,
          productGroup: qa.productGroup,
          category: qa.category,
          netWeight: qa.netWeightKg || 0,
          netWeightKg: qa.netWeightKg || 0,
          grossWeightKg: qa.grossWeightKg || 0,
          brix: 0,
          premiumCadMt: 0,
          maxColor: qa.maxColor,
          location: qa.location || 'Hamilton',
        });
      }
    });

    if (newSkus.length > 0) {
      changed = true;
      setSkus([...updatedSkus, ...newSkus]);
    } else if (changed) {
      setSkus(updatedSkus);
    }
  }, [qaProducts]);

  const [config, setConfig] = useState<CommodityConfig>({
    rawPriceUsdCwt: 13.94,
    oceanFreightUsdMt: 135,
    yieldLossMultiplier: 1.08,
    fxRate: 1.354,
    refiningMarginCadMt: 250,
    freightCostTotalCad: 850,
    volumeMt: 22,
    volumePerLoadMt: 22,
    isDelivered: false,
    deliveredFreightCadMt: 0,
    currency: 'CAD',
    isExport: false,
    exportDutyUsdMt: 361.30,
    origin: 'Hamilton',
    destination: 'Toronto',
    freightType: '',
    useManualFreight: false,
    contractStartDate: new Date().toISOString().split('T')[0],
    contractEndDate: new Date(Date.now() + 90 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
    isPalletCharge: false,
    palletCostCadMt: 15.00,
    palletType: '',
    paymentTerms: undefined,
    customerDifferentialCadMt: 0
  });

  // Auto-calculate market inputs based on contract dates
  useEffect(() => {
    if (marketData.length === 0 || !config.contractStartDate || !config.contractEndDate) return;

    const months = marketData.map(d => d.Month || d.month).filter(Boolean);
    const startIndex = months.indexOf(config.contractStartDate);
    const endIndex = months.indexOf(config.contractEndDate);

    if (startIndex === -1 || endIndex === -1) return;

    const start = Math.min(startIndex, endIndex);
    const end = Math.max(startIndex, endIndex);
    const range = marketData.slice(start, end + 1);

    if (range.length === 0) return;

    const firstRow = marketData[0];
    const monthKeyCalc = Object.keys(firstRow).find(k => k.toLowerCase() === 'month') || Object.keys(firstRow).find(k => k.toLowerCase() === 'date');
    const nonSystemKeys = Object.keys(firstRow).filter(k => k !== 'id' && k !== '__name__' && k !== monthKeyCalc);
    let rawKey = Object.keys(firstRow).find(k => k.toLowerCase().includes('raw sugar') || k.toLowerCase().includes('#11') || k.toLowerCase().includes('raw') || k.toLowerCase().includes('raws'));
    let fxKey = Object.keys(firstRow).find(k => k.toLowerCase().includes('fx') || k.toLowerCase().includes('cad') || k.toLowerCase().includes('exchange'));
    // Fallback: use remaining non-month keys
    if (!rawKey && nonSystemKeys.length >= 1) rawKey = nonSystemKeys[0];
    if (!fxKey && nonSystemKeys.length >= 2) fxKey = nonSystemKeys[1];

    if (rawKey && fxKey) {
      const avgRaw = range.reduce((acc, curr) => {
        const val = typeof curr[rawKey] === 'string' ? parseFloat(curr[rawKey].replace(/[^0-9.]/g, '')) : parseFloat(curr[rawKey]);
        return acc + (val || 0);
      }, 0) / range.length;
      
      const avgFx = range.reduce((acc, curr) => {
        const val = typeof curr[fxKey] === 'string' ? parseFloat(curr[fxKey].replace(/[^0-9.]/g, '')) : parseFloat(curr[fxKey]);
        return acc + (val || 0);
      }, 0) / range.length;

      const newRaw = Math.round(avgRaw * 100) / 100;
      const newFx = Math.round(avgFx * 10000) / 10000;

      if (newRaw !== config.rawPriceUsdCwt || newFx !== config.fxRate) {
        setConfig(prev => ({
          ...prev,
          rawPriceUsdCwt: newRaw,
          fxRate: newFx
        }));
      }
    }
  }, [config.contractStartDate, config.contractEndDate, marketData]);

  // Default the quote tool to the Bulk Granulated SKU (zero product differential)
  // so users start from the simplest baseline. Falls back to the first SKU if
  // no bulk-granulated SKU exists in the catalog.
  const [selectedSkuId, setSelectedSkuId] = useState(() => {
    const bulkGranulated = INITIAL_SKUS.find(s =>
      s.productGroup === 'Bulk' && (s.sugarType === 'Granulated' || /granulated/i.test(s.name)) && (s.premiumCadMt ?? 0) === 0
    ) || INITIAL_SKUS.find(s => s.productGroup === 'Bulk');
    return (bulkGranulated || INITIAL_SKUS[0]).id;
  });
  const [selectedSugarTypeId, setSelectedSugarTypeId] = useState<string>('');
  const [expandedRows, setExpandedRows] = useState<Set<string>>(new Set());
  const [expandedDays, setExpandedDays] = useState<Set<string>>(new Set());
  const [expandedBays, setExpandedBays] = useState<Set<string>>(new Set());

  // CSV export helper — escapes fields and triggers download
  const exportCSV = useCallback((headers: string[], rows: Record<string, any>[], filename: string) => {
    const escape = (val: any) => {
      if (val == null) return '';
      const str = String(val);
      if (str.includes(',') || str.includes('"') || str.includes('\n')) return `"${str.replace(/"/g, '""')}"`;
      return str;
    };
    const csvLines = [headers.join(',')];
    rows.forEach(row => {
      csvLines.push(headers.map(h => escape(row[h])).join(','));
    });
    const blob = new Blob([csvLines.join('\n')], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', filename);
    document.body.appendChild(link); link.click(); document.body.removeChild(link);
    URL.revokeObjectURL(url);
  }, []);

  const weeksList = useMemo(() => Array.from({ length: 52 }, (_, i) => `Week ${i + 1}`), []);
  const daysList = useMemo(() => ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'], []);
  // Generate time slots for a location based on its appointment schedule settings
  const generateTimeSlots = useCallback((startTime: string, endTime: string, durationMin: number) => {
    const [startH, startM] = startTime.split(':').map(Number);
    const [endH, endM] = endTime.split(':').map(Number);
    const startTotal = startH * 60 + startM;
    const endTotal = endH * 60 + endM;
    const slots: string[] = [];
    for (let t = startTotal; t <= endTotal; t += durationMin) {
      const hour = Math.floor(t / 60).toString().padStart(2, '0');
      const min = (t % 60).toString().padStart(2, '0');
      slots.push(`${hour}:${min}`);
    }
    return slots;
  }, []);

  // Get time slots for a specific location from its schedule settings
  const getLocationTimeSlots = useCallback((locationName: string) => {
    const loc = locations.find(l => l.name.toLowerCase().includes(locationName.toLowerCase()));
    const start = loc?.appointmentStartTime || '06:00';
    const end = loc?.appointmentEndTime || '18:00';
    const duration = loc?.appointmentDuration || 30;
    return generateTimeSlots(start, end, duration);
  }, [locations, generateTimeSlots]);

  // Time slots for creation modal — aligned with the location's schedule settings
  const getLocationAllTimeSlots = useCallback((locationName: string) => {
    const loc = locations.find(l => l.name.toLowerCase().includes(locationName.toLowerCase()));
    const start = loc?.appointmentStartTime || '06:00';
    const end = loc?.appointmentEndTime || '18:00';
    const duration = loc?.appointmentDuration || 30;
    return generateTimeSlots(start, end, duration);
  }, [locations, generateTimeSlots]);

  const [skuToConfirm, setSkuToConfirm] = useState<SKU | null>(null);
  const [errorBox, setErrorBox] = useState<string | null>(null);

  const getStatusColor = (status: string) => {
    switch ((status || '').toLowerCase()) {
      case 'completed': return { bg: '#dcfce7', text: '#166534' }; // Green
      case 'in progress': return { bg: '#fef9c3', text: '#854d0e' }; // Light Yellow
      case 'confirmed': return { bg: '#f3e8ff', text: '#6b21a8' }; // Light Purple
      case 'cancelled': return { bg: '#fee2e2', text: '#991b1b' }; // Light Red BG, Dark Red Text
      case 'new': return { bg: '#dbeafe', text: '#1e40af' }; // Blue (Sales Lead)
      case 'qualified': return { bg: '#f3e8ff', text: '#6b21a8' }; // Purple (Sales Lead)
      case 'closed won': return { bg: '#dcfce7', text: '#166534' }; // Green (Sales Lead)
      case 'closed lost': return { bg: '#fee2e2', text: '#991b1b' }; // Red (Sales Lead)
      default: return { bg: 'transparent', text: 'inherit' };
    }
  };


  const getWeekNumber = (dateStr: string) => {
    const [y, m, d] = dateStr.split('-').map(Number);
    const date = new Date(y, m - 1, d);
    // ISO 8601 week number: week 1 is the week containing the first Thursday of the year
    const target = new Date(date.valueOf());
    // Set to nearest Thursday: current date + 4 - current day number (Mon=1, Sun=7)
    const dayNum = (date.getDay() + 6) % 7; // Mon=0, Sun=6
    target.setDate(target.getDate() - dayNum + 3);
    // January 4th is always in week 1
    const jan4 = new Date(target.getFullYear(), 0, 4);
    const jan4DayNum = (jan4.getDay() + 6) % 7;
    const week1Monday = new Date(jan4.valueOf());
    week1Monday.setDate(jan4.getDate() - jan4DayNum);
    const diffMs = target.getTime() - week1Monday.getTime();
    return 1 + Math.round(diffMs / (7 * 24 * 60 * 60 * 1000));
  };

  const toLocalDateString = (date: Date) => {
    const year = date.getFullYear();
    const month = (date.getMonth() + 1).toString().padStart(2, '0');
    const day = date.getDate().toString().padStart(2, '0');
    return `${year}-${month}-${day}`;
  };

  const getDateForWeekDay = (weekNum: number, dayName: string) => {
    // Reference: Wednesday in week 9 should be February 25, 2026
    // Week 9 Monday is Feb 23, 2026
    // Week 1 Monday is Dec 29, 2025
    const week1Monday = new Date(2025, 11, 29); // Dec 29, 2025
    
    const days = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'];
    const dayIdx = days.indexOf(dayName);
    
    const targetDate = new Date(week1Monday);
    targetDate.setDate(week1Monday.getDate() + (weekNum - 1) * 7 + dayIdx);
    
    return targetDate;
  };

  const formatDateMMM_DD = (dateStr: string) => {
    // Parse dateStr manually to avoid UTC shift
    const [y, m, d] = dateStr.split('-').map(Number);
    const date = new Date(y, m - 1, d);
    if (isNaN(date.getTime())) return dateStr;
    return new Intl.DateTimeFormat('en-US', { month: 'short', day: '2-digit' }).format(date);
  };

  // Resolve a product's Product Group name as robustly as possible. The chosen
  // catalog variant is most reliably identified by productKey (a QA product id,
  // or a SKU id for unpaired SKUs); fall back to matching the stored product
  // name against SKU names and QA skuNames. Returns null when nothing matches.
  // Resolve a product's Product Group (which drives the BOL prefix). Prefer the
  // explicit productGroup; when it's blank, fall back to the product's Format
  // (Bulk / Bagged / Tote / Liquid) IF that names a known Product Group — many
  // products carry the Format but not the Group, and both share one vocabulary,
  // so without this a "Bulk" product would wrongly get the default 'P' prefix.
  // Infer a Product Group from a product's name / packaging-format text. The group
  // word is frequently NOT present verbatim — names say "Bag" (group "Bagged") and
  // "Totes" (group "Tote") — and a generic "Bulk Liquid" must resolve to the most
  // specific group, so we match by keyword with a fixed precedence:
  // Liquid > Tote > Bagged > Bulk. Only returns a Product Group that exists in the
  // catalog; null when nothing matches.
  const deriveProductGroup = (...texts: (string | undefined)[]): string | null => {
    const t = texts.filter(Boolean).join(' ').toLowerCase();
    if (!t.trim()) return null;
    const rules: Array<[string, RegExp]> = [
      ['Liquid', /liquid/],
      ['Tote', /tote/],
      ['Bagged', /\bbag/],
      ['Bulk', /\bbulk\b/],
    ];
    for (const [name, re] of rules) {
      if (re.test(t)) {
        const match = productGroups.find(pg => pg.name.trim().toLowerCase() === name.toLowerCase());
        if (match) return match.name;
      }
    }
    return null;
  };
  const groupFromRecord = (rec?: { productGroup?: string; productFormat?: string; name?: string; skuName?: string }): string | null => {
    if (!rec) return null;
    if (rec.productGroup && rec.productGroup.trim()) return rec.productGroup;
    // No explicit group — derive it from the format/name (covers "Bag"→Bagged etc.)
    return deriveProductGroup(rec.productFormat, rec.name, rec.skuName);
  };
  const productGroupOf = (productName?: string, productKey?: string): string | null => {
    if (productKey) {
      const g = groupFromRecord(qaProducts.find(q => q.id === productKey)) || groupFromRecord(skus.find(s => s.id === productKey));
      if (g) return g;
    }
    if (productName) {
      const g = groupFromRecord(skus.find(s => s.name === productName)) || groupFromRecord(qaProducts.find(q => q.skuName === productName));
      if (g) return g;
    }
    // Keyword fallback: infer the group from words in the product name/description
    // itself, so an emailed PO line like "Bulk Liquid Sucrose" still gets the right
    // BOL prefix even before it's matched to a catalog product. The most specific
    // (longest) matching Product Group name wins (so "Liquid" beats "Bulk").
    const n = (productName || '').toLowerCase();
    if (n) {
      const hit = productGroups
        .filter(pg => pg.name && n.includes(pg.name.trim().toLowerCase()))
        .sort((a, b) => b.name.trim().length - a.name.trim().length)[0];
      if (hit) return hit.name;
    }
    return null;
  };

  // The BOL prefix (first character) for a Product Group, taken from the BOL
  // Code column of the Product Groups table. Defaults to 'P' when unknown.
  // Matched case/space-insensitively so e.g. "bulk" still maps to its 'B' code.
  const bolPrefixForGroup = (groupName: string | null | undefined): string => {
    if (!groupName) return 'P';
    const key = groupName.trim().toLowerCase();
    const pg = productGroups.find(g => g.name.trim().toLowerCase() === key);
    return (pg?.bolCode || '').trim().toUpperCase() || 'P';
  };

  // One-time backfill: correct each product's Product Group. New QA products used to
  // default to the first group ("Bulk"), and that wrong value then stuck even for
  // Liquid / Bagged / Tote products — showing the wrong group in the QA table and,
  // because productGroupOf trusts the stored group, charging them the Bulk tolling
  // fee. Re-derive the group from the product's name/format and fix it when the
  // stored value is blank, an unknown group, or the poisoned first-group default
  // that conflicts with a confident derivation. Deliberately-set non-default groups
  // (e.g. someone explicitly chose Bagged) are left untouched.
  const productGroupBackfillRan = useRef(false);
  useEffect(() => {
    if (productGroupBackfillRan.current) return;
    if (productGroups.length === 0) return;
    if (qaProducts.length === 0 && skus.length === 0) return;

    const isKnown = (g?: string) => !!g && productGroups.some(pg => pg.name.trim().toLowerCase() === (g || '').trim().toLowerCase());
    const poison = (productGroups[0]?.name || '').trim().toLowerCase();
    const needsFix = (stored: string | undefined, derived: string): boolean => {
      const s = (stored || '').trim().toLowerCase();
      if (!isKnown(stored)) return true;                    // blank or unknown group
      if (s === derived.trim().toLowerCase()) return false; // already correct
      return s === poison;                                  // only override the default; respect deliberate groups
    };

    const qaFix = new Map<string, string>();
    qaProducts.forEach(q => {
      const derived = deriveProductGroup(q.productFormat, q.skuName);
      if (derived && needsFix(q.productGroup, derived)) qaFix.set(q.id, derived);
    });
    const skuFix = new Map<string, string>();
    skus.forEach(s => {
      const derived = deriveProductGroup(s.productFormat, s.name);
      if (derived && needsFix(s.productGroup, derived)) skuFix.set(s.id, derived);
    });

    if (qaFix.size === 0 && skuFix.size === 0) { productGroupBackfillRan.current = true; return; }
    if (qaFix.size > 0) setQaProducts(prev => prev.map(q => qaFix.has(q.id) ? { ...q, productGroup: qaFix.get(q.id)! } : q));
    if (skuFix.size > 0) setSkus(prev => prev.map(s => skuFix.has(s.id) ? { ...s, productGroup: skuFix.get(s.id)! } : s));
    productGroupBackfillRan.current = true;
  }, [qaProducts, skus, productGroups]);

  // `extraBols` lets a caller that builds several orders in one synchronous
  // pass (before any state commit) reserve the BOLs it has already assigned, so
  // they don't all collide on the same next-number from the stale `orders` state.
  const generateBOLNumber = (lineItems: OrderLineItem[], extraBols: string[] = []): string => {
    // Determine prefix based on bolCode from product groups
    const itemGroups = lineItems.map(item =>
      productGroupOf(item.productName, item.productKey) || 'Other'
    );

    // Prefix is the product group's BOL Code. Single-group order → that code;
    // mixed-group order → the first line item's group code; empty → default.
    const uniqueGroups = new Set(itemGroups);
    let prefix = 'P';
    if (uniqueGroups.size === 1) {
      prefix = bolPrefixForGroup([...uniqueGroups][0]);
    } else if (lineItems.length > 0) {
      prefix = bolPrefixForGroup(productGroupOf(lineItems[0].productName, lineItems[0].productKey));
    }

    // Consider BOLs from BOTH orders AND invoices so sequences never collide,
    // plus any BOLs reserved earlier in the same batch (extraBols).
    const allBols = [
      ...orders.map(o => o.bolNumber || ''),
      ...invoices.map(inv => inv.bolNumber || ''),
      ...extraBols,
    ];

    // Pull the 6-digit counter off any BOL that starts with the same letter,
    // including legacy formats like PREFIX-YEAR-COUNTER.
    const counters: number[] = [];
    for (const bol of allBols) {
      if (!bol) continue;
      if (/^[A-Z]\d{6}$/.test(bol) && bol[0] === prefix) {
        counters.push(parseInt(bol.slice(1), 10) || 0);
      } else if (bol.startsWith(prefix + '-')) {
        const parts = bol.split('-');
        const last = parts[parts.length - 1];
        const n = parseInt(last, 10);
        if (!isNaN(n)) counters.push(n);
      } else if (/^[A-Z]\d+$/.test(bol) && bol[0] === prefix) {
        // Fallback for variable-length numeric tails
        const n = parseInt(bol.slice(1), 10);
        if (!isNaN(n)) counters.push(n);
      }
    }

    let next = (counters.length > 0 ? Math.max(...counters) : 0) + 1;
    // Guarantee no collision with any existing BOL (across orders + invoices)
    const allBolSet = new Set(allBols.filter(Boolean));
    while (allBolSet.has(`${prefix}${String(next).padStart(6, '0')}`)) next++;
    return `${prefix}${String(next).padStart(6, '0')}`;
  };

  // One-time repair: re-number any order whose BOL prefix doesn't match its
  // product group's BOL Code (e.g. emailed Bulk/Liquid orders that imported as
  // "P"). Re-numbers with the correct prefix and cascades the change to linked
  // shipments / invoices / return orders. Completed orders are skipped — their
  // BOLs are on issued documents.
  const fixBolPrefixes = () => {
    const reserved: string[] = [];
    const remap: Record<string, string> = {};
    const newOrders = orders.map(o => {
      const current = (o.bolNumber || '').trim();
      if (!current || !(o.lineItems && o.lineItems.length) || o.status === 'Completed') {
        if (current) reserved.push(current);
        return o;
      }
      const candidate = generateBOLNumber(o.lineItems, reserved);
      if (current[0] === candidate[0]) { reserved.push(current); return o; }
      reserved.push(candidate);
      remap[current] = candidate;
      return { ...o, bolNumber: candidate };
    });
    const count = Object.keys(remap).length;
    if (!count) { setErrorBox('All order BOL prefixes already match their product groups.'); return; }
    setOrders(newOrders);
    setHamiltonShipments(prev => prev.map(s => remap[s.bol] ? { ...s, bol: remap[s.bol] } : s));
    setVancouverShipments(prev => prev.map(s => remap[s.bol] ? { ...s, bol: remap[s.bol] } : s));
    setInvoices(prev => prev.map(inv => inv.bolNumber && remap[inv.bolNumber] ? { ...inv, bolNumber: remap[inv.bolNumber] } : inv));
    setReturnOrders(prev => prev.map(ro => ro.originalBolNumber && remap[ro.originalBolNumber] ? { ...ro, originalBolNumber: remap[ro.originalBolNumber] } : ro));
    setPoIngestNotice(`Fixed ${count} BOL prefix${count === 1 ? '' : 'es'} to match product groups.`);
  };

  // Compute `count` sequential BOL numbers for a product — its product group's
  // bolCode prefix, continuing the sequence past every existing order + invoice
  // BOL. Used to preview/assign BOLs in the order + batch-order menus the moment
  // items/entries are added, before anything is saved.
  const computeBatchBolNumbers = (productName: string, count: number): string[] => {
    if (!productName || count <= 0) return new Array(Math.max(0, count)).fill('');
    const prefix = bolPrefixForGroup(productGroupOf(productName));
    const allBols = [
      ...orders.map(o => o.bolNumber || ''),
      ...invoices.map(inv => inv.bolNumber || ''),
    ];
    let maxCounter = 0;
    for (const bol of allBols) {
      if (!bol) continue;
      if (/^[A-Z]\d{6}$/.test(bol) && bol[0] === prefix) {
        maxCounter = Math.max(maxCounter, parseInt(bol.slice(1), 10) || 0);
      } else if (bol.startsWith(prefix + '-')) {
        const n = parseInt(bol.split('-').pop() || '', 10);
        if (!isNaN(n)) maxCounter = Math.max(maxCounter, n);
      } else if (/^[A-Z]\d+$/.test(bol) && bol[0] === prefix) {
        const n = parseInt(bol.slice(1), 10);
        if (!isNaN(n)) maxCounter = Math.max(maxCounter, n);
      }
    }
    return Array.from({ length: count }, (_, i) => `${prefix}${String(maxCounter + i + 1).padStart(6, '0')}`);
  };

  const updateShipmentStatus = (id: string, status: string) => {
    const allShipments = [...hamiltonShipments, ...vancouverShipments];
    const shipment = allShipments.find(s => s.id === id);

    if (!shipment) return;

    // Update the shipment status in the appropriate list
    const updateFn = (prev: Shipment[]) => prev.map(s => s.id === id ? { ...s, status } : s);
    setHamiltonShipments(updateFn);
    setVancouverShipments(updateFn);

    // If status changed to Completed, update the linked order status, create an invoice and deduct contract volume
    if (status === 'Completed' && shipment.status !== 'Completed') {
      // Update the linked order status to Completed
      const completedOrder = orders.find(o => o.bolNumber === shipment.bol);
      if (completedOrder) {
        setOrders(prev => prev.map(o => o.id === completedOrder.id ? { ...o, status: 'Completed' } : o));
      }
      // Find the contract for this shipment to use contract pricing
      const contract = contracts.find(c => c.contractNumber === shipment.contractNumber);
      const invoiceAmount = contract
        ? shipment.qty * contract.finalPrice  // qty is in MT, finalPrice is $/MT
        : shipment.qty * config.refiningMarginCadMt; // fallback

      const invoiceId = `INV-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
      const linkedOrder = orders.find(o => o.bolNumber === shipment.bol);
      const newInvoice: Invoice = {
        id: invoiceId,
        bolNumber: shipment.bol,
        customer: shipment.customer,
        product: shipment.product,
        po: shipment.po,
        qty: shipment.qty,
        carrier: shipment.carrier,
        amount: invoiceAmount,
        shipmentId: shipment.id,
        date: new Date().toISOString().split('T')[0],
        status: 'Pending',
        lineItems: linkedOrder?.lineItems || [],
        shippingTerms: linkedOrder?.shippingTerms || '',
        location: linkedOrder?.location || '',
        contractNumber: linkedOrder?.contractNumber || linkedOrder?.lineItems.map(li => li.contractNumber).filter(Boolean).join(', ') || '',
      };

      setInvoices(prevInvoices => {
        // Prevent duplicate invoices for the same shipment
        if (prevInvoices.some(inv => inv.shipmentId === id)) return prevInvoices;
        return [...prevInvoices, newInvoice];
      });

      // Track CHEP pallet outbound if applicable
      const matchingOrder = orders.find(o => o.bolNumber === shipment.bol);
      if (matchingOrder?.palletType === 'CHEP') {
        const orderLocation = matchingOrder.location || '';
        let totalPallets = 0;
        for (const li of matchingOrder.lineItems) {
          const matchSku = skus.find(s => s.name === li.productName);
          const qaP = matchSku ? qaProducts.find(q => q.skuId === matchSku.id) : null;
          const upp = qaP?.unitsPerPallet;
          if (upp && upp > 0) {
            totalPallets += Math.ceil(li.qty / upp);
          } else {
            totalPallets += li.qty;
          }
        }
        if (totalPallets > 0) {
          const chepMovement: ChepPalletMovement = {
            id: `CHEP-${Date.now()}-${Math.random().toString(36).slice(2,6)}`,
            date: new Date().toISOString().split('T')[0],
            location: orderLocation,
            type: 'out',
            quantity: totalPallets,
            reference: shipment.bol,
          };
          setChepPalletMovements(prev => [...prev, chepMovement]);
        }
      }

      // Deduct volume from the contract
      if (contract) {
        setContracts(prevContracts => prevContracts.map(c => {
          if (c.contractNumber === shipment.contractNumber) {
            const newVolumeTaken = c.volumeTaken + shipment.qty;
            return {
              ...c,
              volumeTaken: newVolumeTaken,
              volumeOutstanding: c.contractVolume - newVolumeTaken
            };
          }
          return c;
        }));
      }
    }
  };

  const completeAndBillOrder = (orderId: string) => {
    const order = orders.find(o => o.id === orderId);
    if (!order || order.status === 'Completed') return;

    // Set order status to Completed
    setOrders(prev => prev.map(o => o.id === orderId ? { ...o, status: 'Completed' } : o));

    // Find the contract for pricing
    const ordContractNum = order.contractNumber || order.lineItems.map(li => li.contractNumber).filter(Boolean)[0] || '';
    const contract = contracts.find(c => c.contractNumber === ordContractNum);
    const totalWeight = order.lineItems.reduce((sum, item) => sum + item.totalWeight, 0);
    const invoiceAmount = contract
      ? totalWeight * contract.finalPrice  // totalWeight is in MT, finalPrice is $/MT
      : totalWeight * config.refiningMarginCadMt; // fallback

    const invoiceId = `INV-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
    const newInvoice: Invoice = {
      id: invoiceId,
      bolNumber: order.bolNumber,
      customer: order.customer,
      product: order.product || order.lineItems.map(li => li.productName).join(', '),
      po: order.po,
      qty: totalWeight,
      carrier: order.carrier || '',
      amount: invoiceAmount,
      shipmentId: orderId,
      date: new Date().toISOString().split('T')[0],
      status: 'Pending',
      lineItems: order.lineItems,
      shippingTerms: order.shippingTerms || '',
      location: order.location || '',
      contractNumber: order.contractNumber || order.lineItems.map(li => li.contractNumber).filter(Boolean).join(', ') || '',
    };

    setInvoices(prevInvoices => {
      // Prevent duplicate invoices for the same order
      if (prevInvoices.some(inv => inv.shipmentId === orderId)) return prevInvoices;
      return [...prevInvoices, newInvoice];
    });

    // Track CHEP pallet outbound if applicable
    if (order.palletType === 'CHEP') {
      const orderLocation = order.location || '';
      let totalPallets = 0;
      for (const li of order.lineItems) {
        const matchSku = skus.find(s => s.name === li.productName);
        const qaP = matchSku ? qaProducts.find(q => q.skuId === matchSku.id) : null;
        const upp = qaP?.unitsPerPallet;
        if (upp && upp > 0) {
          totalPallets += Math.ceil(li.qty / upp);
        } else {
          totalPallets += li.qty;
        }
      }
      if (totalPallets > 0) {
        const chepMovement: ChepPalletMovement = {
          id: `CHEP-${Date.now()}-${Math.random().toString(36).slice(2,6)}`,
          date: new Date().toISOString().split('T')[0],
          location: orderLocation,
          type: 'out',
          quantity: totalPallets,
          reference: order.bolNumber,
        };
        setChepPalletMovements(prev => [...prev, chepMovement]);
      }
    }

    // Deduct volume from the contract
    if (contract) {
      setContracts(prevContracts => prevContracts.map(c => {
        if (c.contractNumber === ordContractNum) {
          const newVolumeTaken = c.volumeTaken + totalWeight;
          return {
            ...c,
            volumeTaken: newVolumeTaken,
            volumeOutstanding: c.contractVolume - newVolumeTaken
          };
        }
        return c;
      }));
    }

    // Auto-send BOL + COA emails when their respective trigger toggles
    // are on (Email Center → Settings → Triggers). Sends are fire-and-
    // forget — completeAndBillOrder doesn't await them so the UI stays
    // responsive. Each send writes its own emailLog entry; failures land
    // in the log with the error message rather than blocking the bill.
    if (emailSettings.enabled) {
      const completedOrder: Order = { ...order, status: 'Completed' };
      if (emailSettings.triggers.bolOnCompletedAndBilled) {
        sendBolEmail(completedOrder, { triggeredBy: 'automation' });
      }
      if (emailSettings.triggers.coaOnCompletedAndBilled) {
        sendCoaEmail(completedOrder, { triggeredBy: 'automation' });
      }
    }
  };

